INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6156348','Виколишу сокола','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'бабуся',NULL,'Ой, люляй, си, люляй,
Добре тобі спати,
Поки тя колише твоя рідна мати,
Але як тя буде чужа колисати,
Буде тя, синочку, колиска скрипати.

Я повішу колисоньку,
Та й на ябліноньку,
Буде вітер колисати мою дитиноньку,
Буде вітер колисати, дощик накрапляти,
Буде моя дітинонька вгору підростати.

Колишися колисонько від кола до кола,
А я собі виколишу малого сокола.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6156348'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6156348','Виколишу сокола','Ой, люляй, си, люляй,
Добре тобі спати,
Поки тя колише твоя рідна мати,
Але як тя буде чужа колисати,
Буде тя, синочку, колиска скрипати.

Я повішу колисоньку,
Та й на ябліноньку,
Буде вітер колисати мою дитиноньку,
Буде вітер колисати, дощик накрапляти,
Буде моя дітинонька вгору підростати.

Колишися колисонько від кола до кола,
А я собі виколишу малого сокола.');
