INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_615757','Їжак',NULL,'uk','ukraine_1991',NULL,NULL,'Співаник тернопільського туристичного клюбу "Кристал"',NULL,'Їжак маму попрохав, попрохав, попрохав,
Щоби новаком він став, гей, він став, гей!

Хоче мати однострій, однострій, однострій,
І їжацький славний рій, славний рій, гей!

Сухе листя притащить, притащить, притащить,
Вогник жваво запалить, запалить, гей!

А на стійці буде так, буде так, буде так,
Коли стане там їжак, там їжак, гей!

Всі злякаються ввійти, гей, ввійти, гей, ввійти,
Бо він має колючки, колючки, гей!

А на тереновій грі, гей, на грі, гей, на грі,
В кулю скрутиться тоді, гей, тоді, гей!

Щоб хтось тільки покотив, покотив, покотив,
Перший прийде до мети, до мети, гей!','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_615757'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_615757','Їжак','Їжак маму попрохав, попрохав, попрохав,
Щоби новаком він став, гей, він став, гей!

Хоче мати однострій, однострій, однострій,
І їжацький славний рій, славний рій, гей!

Сухе листя притащить, притащить, притащить,
Вогник жваво запалить, запалить, гей!

А на стійці буде так, буде так, буде так,
Коли стане там їжак, там їжак, гей!

Всі злякаються ввійти, гей, ввійти, гей, ввійти,
Бо він має колючки, колючки, гей!

А на тереновій грі, гей, на грі, гей, на грі,
В кулю скрутиться тоді, гей, тоді, гей!

Щоб хтось тільки покотив, покотив, покотив,
Перший прийде до мети, до мети, гей!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6157695','З Полтавського бою','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukraine_before_1917',NULL,NULL,'кобзар Остап Кіндрачук','Виконує: Остап Кіндрачук {1257} Альбом: Остап кіндрачук. Козак-бандурист','З Полтавського бою розбитий гетьман
Біжить безталанний Мазепа.
Кругом тільки тирса та білий туман
В безкрайньому тихому степу.

Спинився гетьман відпочити й на мить
На дальнії могили край степу.
О місяцю, місяцю, згинь не світи,
З-за хмар не дивись на Мазепу.

На тихім Дніпрі ані вітру, ні хвиль,
Безжурні не хиляться лози,
В степу на могилі не шепче ковил,
Лиш роси там ллються, мов сльози.

"Прощай, Україно, і ви ,соколи,
Славетні сини України.
Чи ще доведеться побачить колись
Мені наші милі руїни?

Прощай, Україно, навіки прощай,
Тобі я віддав свою силу!
Ти спомином тихим мене спом''яни
Й мою одиноку могилу."

З Полтавського бою розбитий гетьман
Біжить безталанний Мазепа.
Кругом тільки тирса та білий туман
В безкрайньому тихому степу','["pisni.org.ua", "cat:istorychni", "cat:kozacki", "Історичні пісні", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6157695'), datetime('now')),datetime('now'));
