INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6153644','А я в свої мами-неньки на відході','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано в с. Біла (Тернопільська область), упорядники: Петро Медведик, Олег Смоляк',NULL,'А я в свої мами-неньки
