INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6154972','Бігали дикі кози попід зелені лози','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'1. Бігали дикі кози
Попід зелені лози.

2. За ними козинята,
Поломали ножинята.

3. То в гору, то в долину,
То в ружу, то в калину.

4. Пислала мене мати,
Зелене жито жати.

5. А я жито не жала,
Цвіт з калини ламала.

6. Цвіт з калини ламала,
Та й на хлопців моргала,
Гей-гей, го-го-го, та й на хлопців моргала.

7. А ви хлопці-молодці,
Перекажіть дівочці,
Гей-гей, го-го-го, перекажіть дівочці.    18_2007seniszcz_seans7_Бігали дикі кози попід зелені лози','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6154972'), datetime('now')),datetime('now'));
