INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159178','Козак уїзжає','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Козак уїжджає,
Дівчина заплаче,
Ой, дівчина заплаче,
Ой, не кидай, козаче.

Ой, якби ж я знала,
Що ти кидать будеш,
Ой, то я б твоє личко,
Ой, лиш змалювала.

Личко змалювала,
Ще й позолотила,
Ой, ще й позолотила,
До стінки прибила.

До тієї стінки,
Що шити сідаю,
Ой, до тії кроваті,
Що спати лягаю.

Ой, чи шила, не шила,
Взяла постилила,
Ой, чи спала, не спала,
Ой, взяла поцілувала','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159178'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6159178','Козак уїзжає','Козак уїжджає,
Дівчина заплаче,
Ой, дівчина заплаче,
Ой, не кидай, козаче.

Ой, якби ж я знала,
Що ти кидать будеш,
Ой, то я б твоє личко,
Ой, лиш змалювала.

Личко змалювала,
Ще й позолотила,
Ой, ще й позолотила,
До стінки прибила.

До тієї стінки,
Що шити сідаю,
Ой, до тії кроваті,
Що спати лягаю.

Ой, чи шила, не шила,
Взяла постилила,
Ой, чи спала, не спала,
Ой, взяла поцілувала');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159151','Де ж той, мати, терен','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 12.08.1993 Касета 3',NULL,'Де ж той, мамо, терен?
Піду обламаю.
Де ж те, моє щастя?
Піду пошукаю.

Не ламай же терену,
Бо він ще зелений,
Не шукай же щастя,
Воно утопленнє.

Не раз тебе, доню,
В квітах я купала.
Не раз тобі щастя
У Бога благала.

Зеленого терну
Не треба ламати.
Як немає щастя,
Не треба шукати.

Чи ж ти мене, мамо,
В квітах не купала?
Чи ж ти мені, мамо,
Щастя не бажала?

В квітах я купала,
Любистком вмивала,
А щастя не дала,
Бо й сама не мала','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159151'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6159151','Де ж той, мати, терен','Де ж той, мамо, терен?
