INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6157972','Чуєш, чуєш, пане-брате','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'пісенник ОУМ "Спадщина"',NULL,'Чуєш, чуєш, пане-брате, вдарив тулумбас.
Вже збирає товариство кошовий наказ.
Вже на Дніпрі крига скресла, повінь гоготить.
Пора чайки лаштувати і на турка йти,
Із неволі визволяти братів і сестер,
Хто на каторзі проклятій з відчаю не вмер.

Приспів:
Хай дрижить Стамбул, Скутара,
Порта хай тремтить.
Доки є козак на світі - Україні жить.
Гей, гей, славі жить віки.
Її в битвах здобували мужні козаки.
Гей, гей, будем жить віки,
Бо на те ми запорожці мужні козаки.

Чуєш, чуєш, пане-брате, як земля рида,
Із очей не сльози ллються, ллється кров руда.
Слава їхніми серцями дихає до хмар,
Край свій рідний бережіте ви від яничар!
Хай напасника лихого кара скрізь чека,
Хай ніколи не здригнеться рука козака!','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6157972'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6157972','Чуєш, чуєш, пане-брате','Чуєш, чуєш, пане-брате, вдарив тулумбас.
Вже збирає товариство кошовий наказ.
Вже на Дніпрі крига скресла, повінь гоготить.
Пора чайки лаштувати і на турка йти,
Із неволі визволяти братів і сестер,
Хто на каторзі проклятій з відчаю не вмер.

Приспів:
Хай дрижить Стамбул, Скутара,
Порта хай тремтить.
Доки є козак на світі - Україні жить.
Гей, гей, славі жить віки.
Її в битвах здобували мужні козаки.
Гей, гей, будем жить віки,
Бо на те ми запорожці мужні козаки.

Чуєш, чуєш, пане-брате, як земля рида,
Із очей не сльози ллються, ллється кров руда.
Слава їхніми серцями дихає до хмар,
Край свій рідний бережіте ви від яничар!
Хай напасника лихого кара скрізь чека,
Хай ніколи не здригнеться рука козака!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159940','Бог народився у місті Вифлиємі','Українська народна пісня. Виконує: Остап Кіндрачук','uk','ukr_ssr_1919_1991',NULL,NULL,'Остап Кіндрачук','Цю колядку колядували повстанці на Різдво в середині 40-их в с.Котиківка Івано-Франківської обл. на постої у батька кобзаря Остапа Кіндрачука Юрія.','Бог народився у місті Вифлиємі
У стаєнці.
Йому радіють усі українці
На землі.

І ми тебе просим,
Ісусе рожденний, хоч в ярмі:
Зглянься над тими,
Що плачуть-ридають у тюрмі.

Тих пошли до неба,
Що життя віддали за народ,
І тих, що вмерли
У східній Україні на голод.

То кати червоні
Братів вигубили нам рідних,
Сорок міліонів чекають до бою
Помстити їх.

А Степан Бандера —
Він був ув''язнений, він верне,
Київ відбере від катів червоних
Раз на все.

І задзвонять дзвони, і затрублять труби
У слушний час.
Ми підем до бою,
Ісусе рожденний, спаси нас.','["pisni.org.ua", "cat:christian", "cat:istorychni", "cat:kolyadky", "cat:povstanski", "Пісні на християнську тематику", "Історичні пісні", "Колядки", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159940'), datetime('now')),datetime('now'));
