INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6160093','Школо, прощавай','Музика: Леся Соболевська Слова: Леся Соболевська. Виконує: Ірина Ткачик','uk','ukraine_1991',NULL,NULL,'Авторська нотна збірка "Світ на долоні"',NULL,'1.
