INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6153940','Весільні коломийки','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'записано в с. Біла (Тернопільська область), упорядники: Петро Медведик, Олег Смоляк',NULL,'А я собі господиня,
В мене хата, в мене скриня,
Я по хаті походжаю
Та й ключами подзвоняю.

А наш дружба любив дружку,
Зробив стежку без петрушку.
Ой, щоби то Пан Біг дав,
Щоби дружба дружку взяв.

Ой, Марисю, ходи сюда,
Побавимся, моя люба.
А кінь здохне, шкіра буде,
А Марися моя буде.

В коло, хлопці, в коло, в коло,
Нема хлопця, як Микола,
А в Миколи одна хата:
Штири сніпки, одна лата.

Святий Боже, святий кріпкий,
Я з Нетреби, а ти звідки?
На капусті дрібна роса,
Вибачайте, що я боса.

Там то брови, там то очі,
Цілуй, цілуй: ще ся хоче.
Капустяне листя Куру,
Єдну люблю, десять дуру.

Покайся, ударся в груди,
А будут ще з тебе люди.
А я хлопець без єдвабу (шовку)
Нема дівки, - беру бабу.','["pisni.org.ua", "cat:kolomyyky", "cat:vesilni", "cat:zhartivlyvi", "Коломийки", "Весільні пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6153940'), datetime('now')),datetime('now'));
