INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6159776','Знайшли в мене в почках камінь','Українська народна пісня. Виконує: Фольклорний ансамбль села Межирич','uk','ukraine_before_1917',NULL,NULL,'Фольклорний архів ансамблю "Божичі". Запис в с.Межирич (Маврино) Павлоградського р-ну Дніпропетровської обл. 22.04.1992 Касета 5',NULL,'Знайшли в мене в почках камінь,
Кажуть: буде мені амінь,
Кукуріку-ку-ку-ку!

Жінка моя як узнала
Та й пораду мені дала,
Кукуріку-ку-ку-ку!

Чоловіче мій, серденько,
Їдь у Трускавець швиденько,
Кукуріку-ку-ку-ку!

Пий нафтусю та лічися
Та гляди там, не влюбися,
Кукуріку-ку-ку-ку!

Як я перший раз лічився,
Ні на кого не дивився,
Кукуріку-ку-ку-ку!

На другий день пив нафтусю,
Задивився на Марусю,
Кукуріку-ку-ку-ку!

Пили, їли, веселились,
Поки гроші не скінчились,
Кукуріку-ку-ку-ку!

Пишу листа своїй жінці:
Найшли камінь ще й в печінці,
Кукуріку-ку-ку-ку!

Пишу: мила не журися,
Пришли гроші, не барися,
Кукуріку-ку-ку-ку!

Жінка моя розум мала,
Мені грошей не прислала,
Кукуріку-ку-ку-ку!

Мені грошей не прислала,
Сама сюди завітала,
Кукуріку-ку-ку-ку!

Сама сюди завітала,
Нас з Марусею застала,
Кукуріку-ку-ку-ку!

Била дрюком аж трішало,
З почок камінь виганяла,
Кукуріку-ку-ку-ку!

Тепер жінка розум має,
На курорти не пускає,
Кукуріку-ку-ку-ку!

На курорти не пускає,
Сама туди виїжджає,
Кукуріку-ку-ку-ку!

Сама туди виїжджає,
Мені гроші висилає,
Кукуріку-ку-ку-ку!','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6159776'), datetime('now')),datetime('now'));
