INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6162195','Вийди-вийди, сонечко','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'З пам’яті, з допомогою співклубників','Пісня існує у кількох версіях','Вийди, вийди, сонечко,
