INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6165348','Баю-бай','Музика: Ігор Іванців Слова: Володимир Наконечний','uk','ukraine_before_1917',NULL,NULL,'http://ivantsiv.at.ua',NULL,'Лю-лі, лю-лі, треба спати,
Йде вже ніченька до хати,
Світить зіронька в віконце,
Спи, маленьке наше сонце.

Приспів:
Баю, баю, бай, бай, бай,
Спи, дитино, засинай,
Спи, малесеньке дитятко,
Вже втомились оченятка.
Баю, баю, бай, бай, бай,
Спи, дитино, засинай,
Баю, бай - засинай.

Лю-лі, лю-лі, треба спати,
Вже поснули пташеня,
Їм матуся у садочку
Теж співала співаночку.

Приспів.

Навіть непосида котик
Смачно спить спіймавши хвостик.
Спи і ти, мій голубочку,
Мій малесенький синочку.

Приспів.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6165348'), datetime('now')),datetime('now'));
