INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6163075','Квіточки','Музика: Олег Макаревич Слова: Олена Лайко. Виконує: Оксана Пекун','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В моїм садочку ростуть квіточки,
Все поливай та поливай.
