INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6167297','Рідний дім','Українська народна пісня','uk','ukraine_1991',NULL,'2001','місцевий форум','Виконує: МНК Альбом: Сурми Звитяги 2001','Ми сьогодні будуємо дім, - рідний дім і зовсім новий.
Треба добре зважити всім, що лежатиме в його основі?
Чи уламки старих руїн, чи дешева заморська полова,
Завтра будемо жити в їм, - а сьогодні - новобудова.

Дім, рідний дім, де тепла і світла доволі,
Дім, рідний дім, хай молитвою повниться він!
Дім, рідний дім...Скільки часу чекали ми волі, -
Дім, рідний дім, подаруй очі дітям своїм...

Нині сієм, а завтра пожнуть, - підросте генерація нова,
Низько вклоняться, чи проклянуть, чи почуємо доброго слова,
Може краще вернутись у храм, та навчитися мудрості тої, -
І прислухавшись віщим словам, будувати с любов''ю к основі...

Дім, рідний дім, де тепла і світла доволі,
Дім, рідний дім, хай молитвою повниться він!
Дім, рідний дім...Скільки часу чекали ми волі, -
Дім, рідний дім, подаруй очі дітям своїм...

Дім, рідний дім, де тепла і світла доволі,
Дім, рідний дім, хай молитвою повниться він,
Дім, рідний дім...Скільки часу чекали ми волі, -
Дім, рідний дім, подаруй очі дітям своїм,
Дім, рідний дім, подаруй очі дітям своїм!','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6167297'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6167297','Рідний дім','Ми сьогодні будуємо дім, - рідний дім і зовсім новий.
Треба добре зважити всім, що лежатиме в його основі?
