INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6166695','Не пий, Ваню','Українська народна пісня. Виконує: Club deMoll','uk','ukraine_before_1917',NULL,NULL,'http://nashe.com.ua/song.htm?id=12638&tab=1',NULL,'Не пий, Ваню, не пий воду,
Вода піде ти на шкоду,
А лем ти ся напий вина,
То є добра медицина.

Придьте хлопці, придьте до нас,
Будеме пити вера, зас,
Того винка червеного,
Што до личка румяного.

Налий, мила, налий до дна,
Ти випити го не годна,
Ми ж підеме гори світом
Черкнеме ся погариком.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6166695'), datetime('now')),datetime('now'));
