INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6167593','Колискова для доні','Слова: Yusmal Smal','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua',NULL,'Спи, Оленко, спи, моя доню,
