INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6166673_l1','pisniua_6166673','YouTube','https://www.youtube.com/watch?v=pjaiDb5kqjI','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6167144','З Новим роком – діти','Музика: Сергій Петросян Слова: Богдан Косопуд. Виконує: Зорянка Лопадчак','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Вітання діткам - "З Новим роком!"
Принесла на хвості сорока.
Вона із лісу прилетіла,
Усіх вітати захотіла.
На дереві високім сіла
На гілці зручно примостилась,
Щоб бачити усіх і все,
Бо слово в маси понесе.

Приспів:
Всіх з Новим роком!      |
З Новим роком! -         |
Кричала з дерева сорока. |
Раділи діти, усміхались  |
І гарно всі колядували.  | (2)

Вітала діток від лисички,
Від горобця і від синички,
Від вовка, мишки, їжака,
Від тигра, лева-вожака.
Косульки й білочки вітали,
Зайці - вітаннячко прислали,
Ведмедик також привітав,
Ще й вулик з медом передав.
Вітала діточок ялина
І горобина, і калина.
Дуби, берези і кущі,
Комахи, дятли, снігурі.

Приспів','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6167144'), datetime('now')),datetime('now'));
