INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6166075','Колискова для сина','Музика: Олександр Кушнарьов Слова: Вадим Крищенко. Виконує: Віктор Шпортько','uk','ukraine_1991',NULL,NULL,'Книга: Крищенко В. Д. Усі ми прагнемо любові: Пісні.-Київ:ВіРА ІНСАЙТ-2003',NULL,'Прилетіли тихі птиці
До вечірньої світлиці.
Принесли на крилах синіх
Сон калачиком для сина.

Приспів:
Спи, маленький хлопчику -
Сонечко жоржинове.
Дуже, дуже хочеться,
Щоб ти зріс людиною.

Хай тобі весна і літо
Посміхнуться білим цвітом,
А зима хай під ногами
Грає білими снігами.

Приспів.

Ждуть поля, ліси і луки
На твої завзяті руки,
Жде земля і все навколо
На твоє правдиве слово.

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6166075'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6166075','Колискова для сина','Прилетіли тихі птиці
До вечірньої світлиці.
Принесли на крилах синіх
Сон калачиком для сина.

Приспів:
Спи, маленький хлопчику -
Сонечко жоржинове.
Дуже, дуже хочеться,
Щоб ти зріс людиною.

Хай тобі весна і літо
Посміхнуться білим цвітом,
А зима хай під ногами
Грає білими снігами.

Приспів.

Ждуть поля, ліси і луки
На твої завзяті руки,
Жде земля і все навколо
На твоє правдиве слово.

Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6167879','Засинай, моє малятко','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'http://www.malecha.org.ua/',NULL,'Засинай, моє малятко,
Закривай ти оченятка,
Хай спокійним сон твій буде
І злий дух тебе не збуде.

Хай тебе оберігають
Світлі янголи із раю
І тобі хай нагадають
Барви квітів твого краю.

Ти лиш очі опусти,
Лихо відпусти, любий.
Ти лиш віру поверни,
Мрію відроди, милий.

Спи спокійно, моє сонце,
Янгол пройде крізь віконце,
Він відгонить лихі сни
І відродить дух весни.

Посміхнешся серед ночі,
Не розплющуючи очі,
Лиш почуєш тихий спів,
Знов повернешся до снів...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6167879'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6167879','Засинай, моє малятко','Засинай, моє малятко,
