INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_61673','Вон, хлопці, вон','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'А вже весна скресла. Збірник гаївок. Львів, 2003.','Дівчата та хлопці беруться за руки роблять коло, співають і виконують дії про які йдеться.','Вон, хлопці, вон,
На горі льон.
На долині маковець,
Котрий царем парубець,
Котрий гроші стрілка,
Сто долярів дівка.
Мої милі сусідоньки,
Просили вас матіноньки:
"Розходіться всі враз!"

..."Повклякайте всі враз!"
..."Повставайте всі враз!"
..."Посходіться всі враз!"
..."Поцілуйтесь всі враз!"','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_61673'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_61673','Вон, хлопці, вон','Вон, хлопці, вон,
На горі льон.
На долині маковець,
Котрий царем парубець,
