INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_61695','Десь тут була подоляночка','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1991','А вже весна скресла. Збірник гаївок. Львів, 2003.','Опис гри: Гурт, стоячи колом, співає. Посередині гурту Подоляночка імітує різні дії: падає, встає, ніби вмивається... (Джерело: Свято гаївок: великодні, весняні пісні та ігри.– Дрогобич: Бескид, 1991.– 52 c.) Гаїлки-Великдень: Українське свято Відродження Світа. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Десь узялася Молода Дівчина. Тут Вона впала до Землі припала. А ми Йому Кінця не знайдем. Листки з приводу цієї Пісні: Вербний Тиждень і Шутка. Про Українські назви місяців Марець і Май. --> Коляда і Великдень: Різдво і Відродження Світа Гаїлки-Великдень — Українське Свято Відродження Світа. (Вибір Пісень)','Десь тут була подоляночка,
Десь тут була молодесенька,
Тут вона впала, до землі припала,
Личка не вмивала, бо води не мала.

Ой встань, встань, подоляночко,
Обмий личко, яко шкляночко,
Возьмися за боки, поскачи три кроки
В горохлянім вінку, бери собі дівку,
Плини по Дунаю, бери дівку скраю.    Мелодія для 1 голосу','["pisni.org.ua", "cat:dytyachi", "cat:narodni", "cat:vesnyanky-hayivky", "Дитячі пісні", "Народні пісні", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_61695'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_61695','Десь тут була подоляночка','Десь тут була подоляночка,
Десь тут була молодесенька,
Тут вона впала, до землі припала,
