INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6168797','Пісня джури','Музика: Олександр Жилінський Слова: Олексій Кононенко. Виконує: Олександр Жилінський','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Мій вусатий дід
Знав, як божий день
Свій козацький рід,
Та співав пісень.
По краплині пив
Я дідові слова,
То — святі скарби,
То — вода жива.

Приспів:
Нагадайте мені, тату,
Дідові пісні.
Запрягайте, любий тату,
Коника мені.
Я від хати і до хати
Буду тих пісень співати,
Бо козакам, рід від роду,
Та й немає переводу.
Гей, гей, гей!
Гей, гей, гей!

Нам роздольний степ
Вірний оберіг.
З нього проростем,
Помагай нам Біг!
Матінка одна
Нам на сотні літ
Лада весняна,
Україна-світ!

Приспів','["pisni.org.ua", "cat:patriotic", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6168797'), datetime('now')),datetime('now'));
