INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6168491','Баю, баю, люлі','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Баю, баю, люлі,
А котику дулі,
А Панасу калачі,
Щоб спав удень і вночі.
А вночі - на печі,
А вранці - на лавці.
Вранці - на лавці,
А вдень - у колисці,
А ввечері - у сінях
На пухових подушках.
Мати буде сповивати,
Панасика годувати.','["pisni.org.ua", "cat:dytyachi", "cat:kolyskovi", "Дитячі пісні", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6168491'), datetime('now')),datetime('now'));
