INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6171491','Достойно є!','Музика: о. В. Б. Мендрунь Слова: о. В. Б. Мендрунь','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Достойно є, о, Божа Мати
Воістину достойно є
Тебе Вседіву величати,
Молитися в ім''я Твоє!

Приспів:
Тебе возносять вишні сили,
Тобі вклонився Серафим,
Ти Бога Слово нам зродила,
Тебе вітаєм разом з Ним!

Достойно є, о Божа Мати,
Воістину достойно є
Тебе, Владичицю, благати,
Коли журба на сполох б''є.

Приспів.

Достойно є, о Божа Мати,
Воістину достойно є
Христове Тіло споживати,
Яке з любов''ю подаєш.

Приспів.

Достойно є, о Божа Мати,
Воістину достойно є -
Життя Ісусові віддати,
Як Богу Ти дала своє.

Приспів.','["pisni.org.ua", "cat:cerkovni", "cat:do-bohorodyci", "Церковні пісні", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6171491'), datetime('now')),datetime('now'));
