INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6172673','Пісня до святого Миколая *','Музика: А. Гнатишин Слова: А. Гнатишин','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Отче Миколає, тебе благаєм,
Вислухай щиро нас
В важкій годині,
В сумній хвилині,
В цей горя і смутку час.

Вся Україна стогне в кайданах,
Кривду й наругу терпить,
Поглянь на неї з висот небесних
Й смуток і біль утоли.

Подай нам силу в борбі за правду,
Зішли потіху в журбі,
Хай залунає пісня побіди,
Пісня на славу тобі.','["pisni.org.ua", "cat:cerkovni", "cat:svyatyy-mykolay", "Церковні пісні", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6172673'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6172673','Пісня до святого Миколая *','Отче Миколає, тебе благаєм,
Вислухай щиро нас
В важкій годині,
В сумній хвилині,
В цей горя і смутку час.

Вся Україна стогне в кайданах,
Кривду й наругу терпить,
Поглянь на неї з висот небесних
Й смуток і біль утоли.

