Пісня на славу тобі.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6171195','Гора Таворська','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Гора Таворська горить красою,
Христос стоїть там вбраний дугою,
Промінням ясним б''є навкруги,
Мов сонце ясне верху гори.

Приспів:
Щоби спасення світу принести,
Преобразився в славі і чести
Сам всемогучий Спас і Христос!

До землі впали учні Христові,
Бо жах прошив їх серця до дна,
Бо притьмив зір їх той блиск чудовий,
Те непоняте чудо Христа.

Приспів.

І слово тихе далося чути,
Перший промовив святий Петро:
"Христе, з Тобою добре нам бути,
Тобі поставим ось тут шатро".

Приспів.

Добре нам бути, Христе, з Тобою,
Чи то в днях слави, чи в днях грози.
Веди нас, просим, все за собою
В край вічний щастя, слави веди.

Приспів.','["pisni.org.ua", "cat:cerkovni", "cat:christ", "Церковні пісні", "Пісні до Ісуса Христа"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6171195'), datetime('now')),datetime('now'));
