INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6171151','Царю небесний, Тройці Святої','Слова: о. Й. Кишакевич','uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Царю небесний, Тройці Святої,
Відвічна правдо, правдо свята,
Ти наповняєш весь світ Собою,
Ти одним скарбом нашим життя!

Всесильний Боже! Лиш через Тебе
Спливає в серця наші життя.
В важку годину, у час потреби
Ти свою ласку на нас зішли!

А наші душі очисть з провини,
Най їх не плямить ні пил гріха,
