INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6173440','Гномик','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'У лісі, лісі темному,
Де зайчики стрибають,
Де сосни величезнії
До неба дістають,
У лісі, лісі темному
Навмисне заблукаю,
Щоб гномика-чарівника
Зустріти прямо тут.

Приспів:
А я скажу вам щиро:
Його я не боюсь!
Цей гном - створіння миле,
Йому я посміхнусь!

У лісі, лісі темному,
Де сонечка немає,
Де птахи перелітні
Дзвіночками дзвенять,
У лісі, лісі темному
Навмисне заблукаю,
Щоб з гномиком-чарівником
Удвох потанцювать.

Приспів. (2)','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6173440'), datetime('now')),datetime('now'));
