INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174348','Ой ну, котку-рябку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Ой ну, котку-рябку,
Та скопай нам грядку
Малу, невеличку,
Як із рукавичку.
Ми посієм маку
Іще й пастернаку
Та посадим квіточок -
Забавляти діточок.
Бо в нас діти маленькі,
Гуляти раденькі.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174348'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6174348','Ой ну, котку-рябку','Ой ну, котку-рябку,
Та скопай нам грядку
