INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_617440','Ой там на Дубі Ворона кряче','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... РОЗСПІВ: Ой- там- на- Ду-у-бі- Во-ро-на- кря-а-че- Ой- там- на- Ду-бі- Во-ро-на- кря-че- А- під- тим- Ду-бом- Дів-чи-на- пла-а-че- Ой- там- на- Ду-бі- Во-ро-на- кря-че- А- під- тим- Ду-бом- Дів-чи-на- пла-че- Прийди-прийди Серденя на Пухові Подушки. Листки з приводу цієї Пісні: Еротичні містерії, тиждень від Катерини 7.12 до Калети. Еротичні містерії, Калета 13.12 - Передріздвяний Святочний час. Стежки до листків про Українські пісні. Староукраїнське духовне вогнище не загасло і все горить. Хай сучасний світ тільки підійде ближче, щоб послухати забуті дорогі голоси, навчитися любові й ласки, відчути його тепло та затишок. Час прийшов, щоб скинути полуду з очей. Час прийшов, я знаю... Вчіть дітей. Бабусі-дідусі оживуть і житимуть у дітях. Якщо ми навчимо їх співати та розуміти стародавні пісні, наші діти стануть завтра розумніші, ніж ми є сьогодні. Вони стануть бабусями-дідусями майбуття. – Народна співачка.','Ой там на Дубі Ворона кряче
Ой там на Дубі Ворона кряче
А під тим Дубом Дівчина плаче

Дві останні стрічки в''язки повторюються.

Ворону бити щоб не крякала
Ворону бити щоб не крякала
Дівча любити щоб не плакала

Ой там під Лісом Дорога Бита
Ой там під Лісом Дорога Бита
Поїхав Милий до Ворожбита

Ворож-вороже всю правду скаже
Ворож-вороже всю правду скаже
З ким Моя Мила спатоньки ляже

Ой ляже-ляже сама з собою
Ой ляже-ляже сама з собою
Права рученька під головою

Права рученька Біла Подушка
Права рученька Біла Подушка
Спить Моя Мила спить Моя Душка

Біла Подушка Біла Перина
Біла Подушка Біла Перина
Спить Моя Мила спить Чорнобрива    Основна мелодія','["pisni.org.ua", "cat:halycki", "Пісні з Галичини"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_617440'), datetime('now')),datetime('now'));
