INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174644','Щедрий вечир, добрий вечир','Українська народна пісня. Виконує: Михайло Трохановський','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.48','Виконує: Михайло Трохановський, с.Поляни','Щедрий вечир, добрий вечир,
Христа, Христа Марія
На престолі стоява, два крижички тримава.
А ви, люде, знайте - наше право дайте!
Наше право невеличке, округлицьке.
Верчений пояс, кручений пояс.

Ще дате нам ковача, виведеме рогача.
Заб''еме му ріг на тот Новий рік.
Коровоньки, вовоньки, а нам ковач на щестє,
На здоровля на тот Новий рік!
Жеби ся вам родили бички-телички,
Як в лісі бучки-ялички','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174644'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6174644','Щедрий вечир, добрий вечир','Щедрий вечир, добрий вечир,
Христа, Христа Марія
На престолі стоява, два крижички тримава.
А ви, люде, знайте - наше право дайте!
Наше право невеличке, округлицьке.
Верчений пояс, кручений пояс.

Ще дате нам ковача, виведеме рогача.
Заб''еме му ріг на тот Новий рік.
Коровоньки, вовоньки, а нам ковач на щестє,
На здоровля на тот Новий рік!
Жеби ся вам родили бички-телички,
Як в лісі бучки-ялички');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174776','Колисала баба діда','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Колисала баба діда,
Колисала баба діда,
Ізвечора до обіда.

- Колиш мене, бабко, колиш,
Колиш мене, бабко,колиш,
Куплю тобі калач за гріш.

Бабка калачика з''їла,
Бабка калачика з''їла,
Колисати діда не хотіла.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174776'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6174776','Колисала баба діда','Колисала баба діда,
Колисала баба діда,
Ізвечора до обіда.

- Колиш мене, бабко, колиш,
Колиш мене, бабко,колиш,
Куплю тобі калач за гріш.

Бабка калачика з''їла,
Бабка калачика з''їла,
Колисати діда не хотіла.');
