INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6173144','Вівці пішли в полонинку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'Вівці пішли в полонинку,
А ягнятка бліють,
А як мамка піде з хати,
То діточки мліють.
Вівці прийшли з полонинки,
А ягнятка скачуть.
Прийшла мамка з роботиці,
Діти вже не плачуть.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6173144'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6173144','Вівці пішли в полонинку','Вівці пішли в полонинку,
А ягнятка бліють,
А як мамка піде з хати,
То діточки мліють.
Вівці прийшли з полонинки,
А ягнятка скачуть.
Прийшла мамка з роботиці,
Діти вже не плачуть.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6172050','Левадов, долинов','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Господь - моя пісня. Збірник релігійних пісень. Упор. Т.Ференц, І.Мельник, О.Костецька. Львів, "Свічадо", 2005.',NULL,'Левадов, долинов несеться звено,
З щебетом пташиним зливаєсь воно.
То Діви Марії днесь празник святий, |
То спрошує Церков побожних дітей.   | (2)

Левадов, долинов дітвора гуде,
Цвіточки збирає, в китиці кладе:
Для Діви Марії звинеся вінок,       |
Славися, Маріє, посеред діток!      | (2)

Прийми цей віночок, о Мати блага,
Рукою своєю храни нас від зла:
Провадь нас ласкаво дорогою життя   |
До неба, де радість, а смутку нема. | (2)    комп''ютерне відтворення','["pisni.org.ua", "cat:cerkovni", "cat:do-bohorodyci", "Церковні пісні", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6172050'), datetime('now')),datetime('now'));
