Шкільний прощальний вальс');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174491','А-а, коточок!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986',NULL,'А-а, коточок!
Украв у баби клубочок
Да поніс до Галі,
Положив на лаві.
Стала Галя котка бить:
- Не вчись, коте, красти,
Да вчися робити,
Черевички шити!
Да не дорогії -
По три золотії;
Да не сіх шевців -
Переяславців;
Да не свого ременю -
Привезено з Кременю;
Не сієї роботи -
Привезені чоботи;
Да не наськії,
Да черкаськії.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174491'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6174491','А-а, коточок!','А-а, коточок!
