INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6172991','Посміхнися, стане веселіш!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'інтернет',NULL,'Посміхнися, стане веселіш!
Посміхнись, на небі сонечко засяє.
Подаруй всім посмішку скоріш,
І вона теплом всіх друзів об''єднає.

Приспів:
І відтоді назавжди танцюватимуть хмарки,
І веселка синє небо розфарбує!
З голубеньких потічків починаються річки,
Ну, а посмішка всім настрій подарує!

Посміхнися, і побачиш ти,
Вже не плакатиме дощик найсумніший.
Добрий ліс позбавиш самоти,
Бо співатимуть там звірі наймиліші.

Посміхнися, стане всім тепліш,
І почуєш, як всі весело співають,
Тож нехай назавжди поскоріш
Щирі посмішки серця нам зігрівають.

Приспів.','["pisni.org.ua", "cat:translations", "Переклади іноземних пісень"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6172991'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6172991','Посміхнися, стане веселіш!','Посміхнися, стане веселіш!
Посміхнись, на небі сонечко засяє.
Подаруй всім посмішку скоріш,
