Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6176271','Перший дзвоник','Музика: Михайло Герц Слова: Михайло Шушкевич','uk','ukraine_1991',NULL,NULL,NULL,'є фонограма','Перший дзвоник продзвенів
В радісну хвилину.
Мов пташинний ніжний спів
В синь небес полинув.

Приспів:
Перший дзвоник, перший дзвоник
Ти дзвени в блакитну рань.
Перший дзвоник, перший дзвоник
Клич дітей в країну знань.
Першу вчительку свою,
Привітали діти.
Посмішками клас розцвів,
Мов осінні квіти.

Із букетами у клас
Йдуть щасливі діти.
Бо прийшов навчання час,
Як же не радіти.

Перше вересня-день знань,
Золотіють квіти.
День надій і сподівань,
З святом любі діти','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6176271'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6176271','Перший дзвоник','Перший дзвоник продзвенів
В радісну хвилину.
Мов пташинний ніжний спів
В синь небес полинув.

Приспів:
Перший дзвоник, перший дзвоник
Ти дзвени в блакитну рань.
Перший дзвоник, перший дзвоник
Клич дітей в країну знань.
Першу вчительку свою,
Привітали діти.
Посмішками клас розцвів,
Мов осінні квіти.

Із букетами у клас
Йдуть щасливі діти.
Бо прийшов навчання час,
Як же не радіти.

Перше вересня-день знань,
Золотіють квіти.
День надій і сподівань,
З святом любі діти');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6173570','Прощавай, рідна школо','Музика: Наталія Май Слова: Наталія Май. Виконує: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Пролунав дзвінок останній,
Соловейком віддзвенів,
Ми йдемо в дорогу дальню
На очах учителів,
На душі бринить тривога,
Занімів порожній клас,
То дитинство босоноге
Проводжає тихо нас...

Приспів:
Прощавай, рідна школо,
Тільки знай, сумуватиму я,
Пам''ятай ті слова золоті:
Ти для нас - найдорожча в житті!

Упадуть на землю роси,
Зійде сонце на поріг,
Дітвора дзвінкоголоса
Тихо стане на поріг
І здійсняться сни пророчі
На стежині будніх днів
І теплом засяють очі
Наших рідних вчителів.

Приспів.

Ти для нас - найдорожча в житті!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6173570'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6173570','Прощавай, рідна школо','Пролунав дзвінок останній,
Соловейком віддзвенів,
Ми йдемо в дорогу дальню
На очах учителів,
На душі бринить тривога,
Занімів порожній клас,
То дитинство босоноге
Проводжає тихо нас...

Приспів:
Прощавай, рідна школо,
Тільки знай, сумуватиму я,
Пам''ятай ті слова золоті:
Ти для нас - найдорожча в житті!

Упадуть на землю роси,
Зійде сонце на поріг,
Дітвора дзвінкоголоса
Тихо стане на поріг
І здійсняться сни пророчі
На стежині будніх днів
І теплом засяють очі
Наших рідних вчителів.

Приспів.

Ти для нас - найдорожча в житті!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6177797','Подорож у веселковий світ знань','Слова: Надія Красоткіна','uk','ukraine_1991',NULL,NULL,'http://krasotkina.com',NULL,'Ми предмети кольорові,
Із веселоньки зійшли,
Різнобарвні, веселкові
Дітям руки подали.

Приспів:
Тож візьміться всі за руки
Дружно, як одна сім''я,
В веселковий світ науки
Підем разом ти і я!

Математика, читання,
І краси високий дух,
І природа, й малювання,
Рідна мова, праця й рух.

Приспів.

Все ми будемо учити
І мудрішати щодня:
Щоб людьми у світі жити,
Нам потрібні всім знання.

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6177797'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6177797','Подорож у веселковий світ знань','Ми предмети кольорові,
