INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6175991','Бодай тя, миленький, качечка копнула (лемківська)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Антологія лемківської пісні, Львів, "Афіша", 2005, с.244','Виконує: Антоніна Прибило','1. Бодай тя, миленький, качечка копнула,
Ти любити не знав, а я тя навчила. (2)

2. Бодай тя, миленький в колесі ломали,
Як мене про тебе люди загваряли. (2)

3. Веселам сой, мамцю, веселам сой, дівко,
Бо я веселого парібка фраїрка. (2)

4. Веселам сой била, ниґда не плакала,
Покаль я віночок на головці мала. (2)

5. Пилам я палюнку солодку і квасну,
Любилам парібків, тепер буду газду','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6175991'), datetime('now')),datetime('now'));
