INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6178','Марічка','(В''ється, наче змійка, неспокійна річка...). Музика: Степан Сабадаш Слова: Михайло Ткач. Виконує: Акорд, Чарівна, Олександр Таранець, Василь Зінкевич, Рушничок, Дмитро Гнатюк, Арсен Мірзоян','uk','ukr_ssr_1919_1991',NULL,'1957','1. Українські народні романси. - К.: В-во АН УРСР, 1961. - с. 386- 387','* Тут за іншим джерелом (усним?) можливий варіант: "Берегом так тихо мовчазний ходжу." Виправлення і допонення: Anrzej (член клубу). Уточнив за збіркою - див. джерело [1]. Першоджерело: Буковина в піснях. - Чернівці, 1957. - с. 201. Пісня написана орієнтовно на початку 1950-х. Цікава додаткова інформація є тут: http://www.doba.cv.ua/index.php? file=news.php&num=312&s=10#pos Гурт Рушничок виконує пісню на іншу мелодію http://chomikuj.pl/WDR/Muzyka+Ukrai*c5*84ska/Narodowa+-+Folk+-+Regionalna/Rushnychok Підбір акордів: Євген Шульга','В''ється, наче змійка, неспокійна річка,
Тулиться близенько до підніжжя гір.
А на тому боці, там живе Марічка,
В хаті, що сховалась у зелений бір.
Як із хати вийде, на порозі стане -
Аж блищить красою широчінь ріки.
А як усміхнеться, ще й з-під лоба гляне:
"Хоч скачи у воду" - кажуть парубки.
Не питайте, хлопці, чом я одинокий
Берегом так пізно мовчазний ходжу. *
Там на тому боці загубив я спокій
І туди дороги я не знаходжу.
Та нехай сміється неспокійна річка,
Все одно на той бік я путі знайду:
"Чуєш, чи не чуєш, чарівна Марічко,
Я до твого серця кладку прокладу."
Акорди:
В''ється, наче змійка, неспокійна річка,
Тулиться близенько до підніжжя гір.
А на тому боці, там живе Марічка,
В хаті, що сховалась у зелений бір.','["pisni.org.ua", "cat:lirychni", "cat:romansy", "Пісні про кохання, ліричні", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6178'), datetime('now')),datetime('now'));
