INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_618178','Нехай буде так!','(Let it be). Музика: Пол Маккартні Слова: Джон Ленон. Виконує: Олександр Сушко, Віктор Сушко','uk','ukraine_1991',NULL,NULL,'Переклад відомої пісні гурту Бітлз','Дует брати Сушки, неодноразові учасники та лауреати фестивалів "Оберіг" та "Червона рута". Підбір акордів: Віктор Сушко','Коли біда приходить знову -
Мати-Марія до мене йде
Мовити мудре слово "Най буде".

У часи важкі з любовю
Порятунок віднайде,
Поможе мудрим словом "Най буде".

Приспів:
Най буде, най буде, най буде, най буде,
Зі мною мудре слово най буде!
Най буде, най буде, най буде, най буде,
Зі мною мудре слово най буде.

І коли у вас від болю
Серце спокій не знайде,
Майте силу волі - най буде.

Хай нелегка часом доля,
Мати-Марія до мене йде
Мовити мудре словао "Най буде".

Приспів:

Уночі в мою фіранку
Сяйво місяця бліде
Лине до світанку. Най буде.

Під мелодію ранкову
Мати-Марія до мене йде,
Мовити мудре слово "Най буде!','["pisni.org.ua", "cat:translations", "Переклади іноземних пісень"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_618178'), datetime('now')),datetime('now'));
