INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6174797','Колисала баба діда **','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Книга: Дитячий фольклор,Київ,"Дніпро"1986','Миня (дит. слово) - корова','Колисала баба діда
Ізвечора до обіда:
- Ой спи, діду, старий бичку,
А я видою теличку.-
Баба миньку видоїла,
Діду каші наварила.
- Вставай, діду, старий бичку,
Стоїть каша на препічку.','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6174797'), datetime('now')),datetime('now'));
