INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6182879','Весільна осінь','Музика: Олександр Злотник Слова: Володимир Мельников. Виконує: Володимир Мельников','uk','ukraine_1991',NULL,'2010','Авторське подання','У такому варіанті ця пісня пролунала 12.09.2010 на весіллі Сергія і Анжели Саєнків: Ми вітаємо вас! Йде по Києву осінь весільна! Наче Ангел з небес, наречена Анжела у нас. Вже дружина вона, а з коханим – свята і всесильна... "Тож купайтесь в любові", – звертаються гості до вас. Дорогі молодята! Наші рідні, Сергій і Анжела! Ми бажаємо вам – море Квітів, Любові, Тепла! В океані кохання – хай летить ваших мрій каравела. У подружнім житті ви тепер два вітрила - крила. Від кохання батьків у родинах з''являються діти. Виростають вони, "Вже Серьожа – до хмар дістає"... Як радіють батьки... Скоро будуть онукам радіти! Бо і "хата" вже є, і кохання з наснагою є. Дорогі молодята! Наші рідні, Сергій і Анжела! Ми бажаємо вам – море Квітів, Любові, Тепла! В океані кохання – хай летить ваших мрій каравела. У подружнім житті ви тепер два вітрила - крила. ЩИРІ ВІТАННЯ УСІМ МОЛОДЯТАМ УКРАЇНИ!','Ми вітаємо вас! І вітає вас осінь весільна!
Наче Ангел з небес, наречена сьогодні у нас.
Вже дружина вона, а з коханим - свята і всесильна...
"Тож купайтесь в любові", - звертаються гості до вас.

Приспів:
Дорогі молодята! Ви ще зовсім маленька родина!
Ми бажаємо вам - море Квітів, Любові, Тепла!
В океані кохання - хай летить ваших мрій бригантина.
У подружнім житті  ви тепер два вітрила - крила.

Від кохання батьків у родинах з''являються діти.
Виростають вони і весілля їх день настає...
Як радіють батьки... Скоро будуть онукам радіти!
Бо для цього все є. Для кохання і щастя - все є.

Приспів','["pisni.org.ua", "cat:vesilni", "cat:zahalni-cinnosti", "Весільні пісні", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6182879'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6182879','Весільна осінь','Ми вітаємо вас! І вітає вас осінь весільна!
Наче Ангел з небес, наречена сьогодні у нас.
Вже дружина вона, а з коханим - свята і всесильна...
"Тож купайтесь в любові", - звертаються гості до вас.

Приспів:
Дорогі молодята! Ви ще зовсім маленька родина!
Ми бажаємо вам - море Квітів, Любові, Тепла!
В океані кохання - хай летить ваших мрій бригантина.
У подружнім житті  ви тепер два вітрила - крила.

Від кохання батьків у родинах з''являються діти.
Виростають вони і весілля їх день настає...
Як радіють батьки... Скоро будуть онукам радіти!
Бо для цього все є. Для кохання і щастя - все є.

Приспів');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6183195','Про кума','Музика: Ігор Петренко. Виконує: Ігор Петренко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Картопля смажена,
Сало та цибуля,
О-хо-хо-хо,
Жіночка відряджена
І в кишенях дуля,
О-хо-хо-хо,
Слухавку тримаю,
Кума набираю,
О-хо-хо-хо.

Куме, маєм свято,
Не беріть багато!
Куме, маєм свято,
Не беріть багато!
О-хо-хо-хо!

Де одна - там сварка,
А де дві - там бійка,
Тритю мусим пити,
П''ята - будем жити!
Кум брови зсупив,
Капелюха здвинув:
Чверу ти поцупив,
Що ж ми за родина?

Ксьонз бере десяту,
А держава - третю,
Ти ж пробачиш, брате,
Що я вкрав четверту.
Шоста, сьома, восьма
Там, де і десята,
Як так будем жити,
То не буде свята!

Картопля смажена,
Сало та цибуля,
І в кишенях дуля...

Як так будем жити,
То не буде свята!','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6183195'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6183195','Про кума','Картопля смажена,
Сало та цибуля,
О-хо-хо-хо,
Жіночка відряджена
І в кишенях дуля,
О-хо-хо-хо,
Слухавку тримаю,
Кума набираю,
О-хо-хо-хо.

Куме, маєм свято,
Не беріть багато!
Куме, маєм свято,
Не беріть багато!
О-хо-хо-хо!

Де одна - там сварка,
А де дві - там бійка,
Тритю мусим пити,
П''ята - будем жити!
Кум брови зсупив,
Капелюха здвинув:
Чверу ти поцупив,
Що ж ми за родина?

Ксьонз бере десяту,
А держава - третю,
Ти ж пробачиш, брате,
Що я вкрав четверту.
Шоста, сьома, восьма
Там, де і десята,
Як так будем жити,
То не буде свята!

Картопля смажена,
Сало та цибуля,
І в кишенях дуля...

Як так будем жити,
То не буде свята!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6183454','Веселі чобітки','Музика: А. Філіпенко Слова: Т. Волгіна','uk','ukraine_before_1917',NULL,NULL,'Єфросинія Душна, Андрій Душний. Бандуро, дзвени, не стихай! /Збірка творів для учнів початкових мистецьких навчальних закладів. – Львів: ТеРус, 2005. – 44 с.',NULL,'Чобітки веселі в мене,
Як піду гуляти,
Чобіточки тупотять,
Хочуть танцювати.

Я бабусі помагала,
Тарілочки мила,
У таночок як пішла,
Глечика розбила.

Гопака я у неділю
Танцювати вчилась,
Перекинула відро -
Мама розгнівилась!

Ви не смійтеся, малята,
Чи ж я винувата,
Що веселі отакі
Маю чоботята.    Фонограма мінус (mp3)','["pisni.org.ua", "cat:dytyachi", "cat:zhartivlyvi", "Дитячі пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6183454'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6183454','Веселі чобітки','Чобітки веселі в мене,
Як піду гуляти,
Чобіточки тупотять,
Хочуть танцювати.

Я бабусі помагала,
Тарілочки мила,
У таночок як пішла,
Глечика розбила.

Гопака я у неділю
Танцювати вчилась,
Перекинула відро -
Мама розгнівилась!

Ви не смійтеся, малята,
Чи ж я винувата,
Що веселі отакі
Маю чоботята.    Фонограма мінус (mp3)');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6183454_l1','pisniua_6183454','YouTube','https://www.youtube.com/watch?v=9ayB1plfI-E','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6182899','Вишиванка','Музика: невідомий Слова: Микола Сингаївський','uk','ukraine_1991',NULL,NULL,'http://duda.org.ua',NULL,'Ми своїми вправними руками
Вишивали рушничок для мами,
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Є на ньому півники святкові,
Є на ньому квіти малинові,
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Синя нитка — птиці прилітають,
А червона - квіти зацвітають.
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Листя вишиваєм зеленаве,
Сонце вишиваємо ласкаве,
Щоб на свято маму привітати,
Нашу радість їй подарувати.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6182899'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6182899','Вишиванка','Ми своїми вправними руками
Вишивали рушничок для мами,
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Є на ньому півники святкові,
Є на ньому квіти малинові,
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Синя нитка — птиці прилітають,
А червона - квіти зацвітають.
Щоб на свято маму привітати,
Нашу радість їй подарувати.

Листя вишиваєм зеленаве,
Сонце вишиваємо ласкаве,
Щоб на свято маму привітати,
Нашу радість їй подарувати.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6183776','Пісня Литві','Музика: Олег Покальчук Слова: Олег Покальчук. Виконує: Олег Покальчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'На вежі Гедиміноса
І на Високім Замку
Час піднімає прапори
Вітрилами надій,
І їхні лісові брати,
І наші партизани
Тепер спокійно спатимуть
У славі січовій!

Приспів:
Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
На спільному шляху вперед,
Завжди вперед і вгору!
Хай помагають нам святі
І Вітовтас, і Юр!

Майбутнє наших націй знов
Поставлено на карту,
Чи виграв, чи програв,
Та честь ніхто не відбере,
Ми теж чекаєм виходу
З радянського плацкарту,
Бо поїзд сунеться назад,
А час іде вперед.

Приспів.

Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
Шлях до свободи лиш один -
Завжди вперед і вгору!
Кремлівський мур також паде,
Як і Берлінський мур!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6183776'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6183776','Пісня Литві','На вежі Гедиміноса
І на Високім Замку
Час піднімає прапори
Вітрилами надій,
І їхні лісові брати,
І наші партизани
Тепер спокійно спатимуть
У славі січовій!

Приспів:
Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
На спільному шляху вперед,
Завжди вперед і вгору!
Хай помагають нам святі
І Вітовтас, і Юр!

Майбутнє наших націй знов
Поставлено на карту,
Чи виграв, чи програв,
Та честь ніхто не відбере,
Ми теж чекаєм виходу
З радянського плацкарту,
Бо поїзд сунеться назад,
А час іде вперед.

Приспів.

Вперед, Литво!
Вперед! Вперед!
Пробач, що ми не поруч!
Нам теж не місце у музеї
Воскових фігур!
Шлях до свободи лиш один -
Завжди вперед і вгору!
Кремлівський мур також паде,
Як і Берлінський мур!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6182252','Коломийки','Музика: Володимир Шинкарук Слова: Володимир Шинкарук. Виконує: Володимир Шинкарук','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Хтось у двері мені стукав, вибив аж три дошки,
Думав я, то Дід Мороз, а то - відморозки.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

А чого Верховну Раду "Радою" назвали?
Бо радіють депутати, що туди попали.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Теща мені, наче мати - може все дістати!
Ой, якби ж то вона знала, як мене дістала!

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Зустрічаються два кума у полі за гаєм:
- Ви корову вже доїли?
- Ні, ще доїдаєм...

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Той, хто продає пальне, -  не оре й не сіє,
Лиш компанія "Лукоіл" - цибуля й олія!

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Хто візьме горілку "Пісня" й стане її пити,
Буде ввечері співати, вранці - буде вити!

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Я уже в такому віці, що не випадково
Більш лякає згода жінки, ніж її відмова.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Виїхав з села Поплавський - не залишив сліду,
А село із нього й досі ну ніяк не їде.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Ходять наші футболісти по полю, мов тіні,
В Англії футбол родився, а вмер в Україні.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Українські водії закричали ґвалтом -
На дорогах зійшов сніг разом із асфальтом...

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

У коханні - третій зайвий, будемо відверті -
Чоловік "застукав" жінку...  молотком до смерті.

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!

Я жінок усіх вітаю, і скажу, без жарту:
Краще бути "первой Майєй", ніж "восьмою Мартой"!

Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!
Гей, шіді-ріді-дам, шіді-ріді-дана-дана,
Гей, шіді-ріді-дам, шіді-ріді-дана!','["pisni.org.ua", "cat:kolomyyky", "cat:zhartivlyvi", "Коломийки", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6182252'), datetime('now')),datetime('now'));
