INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6184542','Каперуш','(Ой, вийду я на майдан). Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256 с.','Опис гри: Учасники гри йдуть по колу, співаючи пісню. У колі один хлопець із хустиною в руках іде проти руху. Обирає якусь дівчину, пританцьовуючи, веде її на середину кола, простеляє хустку. Доки звучить перегра, вони удвох стають на ній на коліна і цілуються. По тому хлопець приєднується до гурту, а дівчина так само йде по колу і обирає собі пару...','Ой, вийду я на майдан,
Вийду погуляти,
Кого люблю, тому дам
Личко цілувати.

Маю хустку вишивану
На чотири роги,
Кого люблю - поцілую,
Постелю під ноги.

Маю хустку вишивану
На чотири кінці,
Кого люблю - поцілую
Стану на колінця.','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6184542'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6184542','Каперуш','Ой, вийду я на майдан,
