INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6185144','Ой, на Купала, на Івана','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, на Купала, на Івана
Вийшла Ганнуся гарно вбрана.

На неї хлопці зглядаються,
А зачепити стидаються.

Один Василько не встидався,
Взяв за рученьку, привітався.

Ой, ти Ганнусю, ой ти, ой ти,
Звідки до тебе зайти, зайти?

Садком, Васильку, садком, садком,
В мене горілка з медком, з медком.

Садком, Васильку, стежечками,
В мене горілка з ягідками.

Садком, Васильку, долиною,
В мене горілка з калиною.','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6185144'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6185144','Ой, на Купала, на Івана','Ой, на Купала, на Івана
Вийшла Ганнуся гарно вбрана.

На неї хлопці зглядаються,
А зачепити стидаються.

Один Василько не встидався,
Взяв за рученьку, привітався.

Ой, ти Ганнусю, ой ти, ой ти,
Звідки до тебе зайти, зайти?

Садком, Васильку, садком, садком,
В мене горілка з медком, з медком.

Садком, Васильку, стежечками,
В мене горілка з ягідками.

Садком, Васильку, долиною,
В мене горілка з калиною.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6185297','Ой летіла біла пава','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Красна весна, тихе літо. Українські народні календарні пісні весняно- літньої пори з репертуару етнографічного хору "Гомін" та Київського Кобзарського Цеху. /Упорядники: Ященко Л. І., Міщенко К. А./ - Київ, 2007. - 256',NULL,'Ой, летіла біла пава до бору,
Заганяла челядоньку до двору.      | (2)

Іди, іди, челядонько, до двору,
Не запалюй біле личко по полю.     | (2)

Ой, до кінця, женчики, до кінця,
Та й підемо додомоньку за сонця.   | (2)

А нашая хазяєчка молоденька,
Да зварила на вечерю горобейка.    | (2)

А нашая хазяєчка велика,
Да зварила на вечерю індика.       | (2)

Ой, зварила на вечерю індика,
Да буде вам горілочка ще й музика. | (2)','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6185297'), datetime('now')),datetime('now'));
