INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6223374','Ой, летіла стріла','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'книга народних пісень',NULL,'Ой, летіла стріла
З-за синього моря.
Ой, де ж вона впала?
На вдовинім полі.

Кого ж вона вбила?
Вдовиного сина,
Немає нікого
Плакати по ньому.
Летять три зозуленьки,
І всі три рябенькі:

Одна прилетіла,
В головоньках сіла.
Друга прилетіла,
Край серденька сіла.
Третя прилетіла
Та в ніженьках сіла.

Що в головках сіла —
То матінка рідна.
Сіла край серденька —
То його миленька.
А в ніженьках сіла —
То його сестриця.

Де матінка плаче,
Там Дунай розлився.
Де плаче сестриця,
Там слізок криниця.
Де плаче миленька,
Там земля сухенька.

Ой, матінка плаче,
Поки жити буде.
А сестриця плаче,
Поки не забуде.
А миленька плаче,
Поки його бачить...','["pisni.org.ua", "cat:narodni", "cat:nostalgia", "Народні пісні", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6223374'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6223374','Ой, летіла стріла','Ой, летіла стріла
З-за синього моря.
Ой, де ж вона впала?
На вдовинім полі.

Кого ж вона вбила?
Вдовиного сина,
Немає нікого
Плакати по ньому.
Летять три зозуленьки,
І всі три рябенькі:

Одна прилетіла,
В головоньках сіла.
Друга прилетіла,
Край серденька сіла.
Третя прилетіла
Та в ніженьках сіла.

Що в головках сіла —
То матінка рідна.
Сіла край серденька —
То його миленька.
А в ніженьках сіла —
То його сестриця.

Де матінка плаче,
Там Дунай розлився.
Де плаче сестриця,
Там слізок криниця.
Де плаче миленька,
Там земля сухенька.

Ой, матінка плаче,
Поки жити буде.
А сестриця плаче,
Поки не забуде.
А миленька плаче,
Поки його бачить...');
