INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_622673','Оксано','Українська народна пісня. Виконує: Не журись!','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,NULL,'Оксано, Оксано, я чую твій голос
Мені рідний вітер з України приніс.
Я чую як стогне потоптаний колос    |
І бачу я очі твої, повні сліз.      | (2)

Оксано, Оксано, давно ми розстались,
Та прийде ще час - ми зустрінемось знов.
Коханою була і нею зосталась,
Оксано ти щастя моє і любов.

Коли ж на далекій, святій Україні
Засяє нам знову свободи зоря
До вас я прилину на крилах орлиних |
Оксано моя, Україно моя.           | (2)','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_622673'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_622673','Оксано','Оксано, Оксано, я чую твій голос
