INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6220075','Невістка','Музика: М. Мазур Слова: М. Мазур. Виконує: М. Мазур','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Горнулась пташечка до матері,
А мати - до дитини,
Тепер тебе уже засватали,
Прощаємся ми нині.
А сонце сходило, торкалось їх
І квіти розквітали.
Дві пташки плакали,     |
Дві пташки плакали,     |
Дві пташки плакали,     |
Дві пташечки прощались. | (2)

Приспів:
Жінкою, невісткою,
Радісною звісткою,
Лине доня сватана у чужі сади.
Казкою та піснею,
Ще з дитинства звісною,
Лине серце матері з донею туди.
Буде серце матері з донею завжди!

Серця їх, наче пісня завчена,
Донині поруч бились,
Та вже усьому доня навчена,
Бо мати гарно вчила.
Любов покликала, і в тому суть,
Гніздечко покидає,
А мати вперше           |
В самостійну путь       |
Дитину проводжає.       | (2)

Приспів.

Горнулась пташечка до матері,
А мати - до дитини,
Тепер тебе уже засватали,
Прощаємся ми нині.
А сонце сходило, торкалось їх
І квіти розквітали.
Дві пташки плакали,     |
Дві пташки плакали,     |
Дві пташки плакали,     |
Дві пташечки прощались. | (2)','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6220075'), datetime('now')),datetime('now'));
