INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6223246','Пісня про школу','Музика: Н. Дремлюга Слова: Т. Масенко','uk','ukraine_1991',NULL,NULL,'інтернет',NULL,'Мама двері відчиня,
Проводжа до школи.
Не забудем цього дня
Ми в житті ніколи!

А татусь нам говорив,
Як ішли ми в школу:
Поважайте вчителів,
Слухайтесь у всьому!

Не забудем цього дня
Ми в житті ніколи!
Найсвітліший край у нас,
Найсвітліші школи!','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6223246'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6223246','Пісня про школу','Мама двері відчиня,
Проводжа до школи.
Не забудем цього дня
Ми в житті ніколи!

А татусь нам говорив,
Як ішли ми в школу:
Поважайте вчителів,
Слухайтесь у всьому!

Не забудем цього дня
Ми в житті ніколи!
Найсвітліший край у нас,
Найсвітліші школи!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6223246_l1','pisniua_6223246','YouTube','https://www.youtube.com/watch?v=ILVjKGZknD0','video',NULL,1);
