INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_622848','Подай, дівчино, руку на прощання','Українська народна пісня. Виконує: Етнографічний хор Гомін','uk','ukr_ssr_1919_1991',NULL,NULL,NULL,'* відміна: Його поховали вірні побратими Під кущем червоної калини','Подай, дівчино, руку на прощання,
Може в останній вже раз.
Прийшла година, час іти до бою,
Мушу сповняти наказ.

Ми йшли до бою темної ночі,
А ясні зорі сіяли,
Гармати били, а ми наступали,
Один за одним падали.

Бачив я, бачив раненого друга,
Він впав на землю ще живий.
З грудей червона кров текла рікою,
Останні слова говорив:

"Напишіть до батька, напишіть до неньки
Напишіть до любої дівчини,
Що гостра куля грудь мою пробила
В бою за волю України."

Не було там батька, не було там неньки,
Не було там любої дівчини,
Лиш товариші його поховали,*
Оркестра жалібно заграла','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_622848'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_622848','Подай, дівчино, руку на прощання','Подай, дівчино, руку на прощання,
Може в останній вже раз.
Прийшла година, час іти до бою,
