INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6216776','У добрий час','Музика: Іван Карабиць Слова: Микола Сом. Виконує: Тріо "Золоті Ключі"','uk','ukraine_before_1917',NULL,NULL,'Аудіозапис',NULL,'Усміхнися нам, ясная доле,
То любов лебедіє жива.
А життя перед нами, як поле,
Де посіяні теплі слова.

Приспів:
У добрий час,
На довгий вік,
На щастя,
На кохання
Твори життя із року в рік,
Стрічай зорю світання.

В молодому зеленому житі
Не загубиться стежка мала.
Та стежина єдина у світі
Нареченими нас нарекла.

Приспів.

Стане день молодий і зелений,
І народиться пісня нова,
Де цілуються з вербами клени,
А з вітрами шепоче трава.

Приспів','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6216776'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6216776','У добрий час','Усміхнися нам, ясная доле,
То любов лебедіє жива.
А життя перед нами, як поле,
