Приспів');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6221252','Лісова Школа Булавних-26','Слова: О. Яворський, А. Спех','uk','ukraine_1991',NULL,NULL,'співаник Лісової Школи',NULL,'Приїхало сюди 16,
Аби життя пізнати лісове,
Згуртувати дух співпраці
І стати абсольвентами...

Приспів:
Було би зовсім не зле,
Якби тут було ШБ,
Ми б не страждали від нудьги
Ніколи!
Було би зовсім не зле,
Як до ЛШ додати ШБ,
Буде жити дружно ЛШБ!

В вогонь і в воду ми піти готові,
Здоровий дух у тілі нашому живе,
ЛШ - найкраща школа пластунові,
Хороше на ЛШ життя, але...

Приспів.

А місяць одиноким оком
Пасе отари на гірських хребтах,
Спливе туман у діл Гнилим потоком
І огортає смутком у серцях.

Приспів.

Юнацька пісня лине над горою,
Над Грабовець, аж до Пшонця летить,
ШБ, ЛШ в думках завжди з тобою,
І ось настала довгожданна мить!

Радість в серцях оживе,
В гості прибуло ШБ,
Заіскрились погляди юнацькі,
Ми так чекали тебе,
Наше кохане ШБ,
Хай співає разом ЛШБ!','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6221252'), datetime('now')),datetime('now'));
