INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6234477','На північнім нашім кордоні','Музика: В. Пастушок. Виконує: В. Пастушок','uk','ukr_ssr_1919_1991',NULL,NULL,'повстанський зошит з піснями',NULL,'На північнім нашім кордоні,
Аж ген під наш Берест і Пінськ,
Ідуть УПА славні загони
На захист родинних огниськ!

Вітає їх людність Полісся,
На очах сріблиться роса,
Що хутір, то курінь розлігся,
Що хата - твердині краса!

Вставай, український народе!
УПА то є кузні горно,
Нас кличе життя всіх до згоди,
Нас в''яже тризуб у одно!

І віра, і пісня, і мова
Від *** по Дунай,
Їх води належать Дніпрові,
Їх думка - то вільний Наш Край!

Ідем, щоб соборно затерти
Кордони неволі й ганьби,
Ідем воскресити із мертвих,
Що ворог поклав у гроби.

Хай лине наш марш сей упівський,
З-над Буга аж ген по Кубань,
Зробив його гнів український,
У загравах грізних повстань!

На північнім нашім кордоні,
Аж ген під наш Берест і Пінськ,
Ідуть УПА славні загони
На захист родинних огниськ!','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6234477'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6234477','На північнім нашім кордоні','На північнім нашім кордоні,
Аж ген під наш Берест і Пінськ,
Ідуть УПА славні загони
На захист родинних огниськ!

Вітає їх людність Полісся,
На очах сріблиться роса,
Що хутір, то курінь розлігся,
Що хата - твердині краса!

Вставай, український народе!
УПА то є кузні горно,
Нас кличе життя всіх до згоди,
Нас в''яже тризуб у одно!

І віра, і пісня, і мова
Від *** по Дунай,
Їх води належать Дніпрові,
Їх думка - то вільний Наш Край!

Ідем, щоб соборно затерти
Кордони неволі й ганьби,
Ідем воскресити із мертвих,
Що ворог поклав у гроби.

Хай лине наш марш сей упівський,
З-над Буга аж ген по Кубань,
Зробив його гнів український,
У загравах грізних повстань!

На північнім нашім кордоні,
Аж ген під наш Берест і Пінськ,
Ідуть УПА славні загони
На захист родинних огниськ!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6233746','Синії очі','Музика: Богдан Весоловський Слова: Володимир Сосюра. Виконує: Антін Дербіш, Василь Бокоч','uk','ukraine_1991',NULL,NULL,'аудіозапис','Танго * - не зміг розібрати слова','В твоїх очах - душа твоя
Все та ж кохана, юна.
Для мене радісно сія,
Торкає серця струни,
І струни радісно звучать
Про дні, сади квітчасті,
В твоїх очах небес*
І щастя, щастя, щастя...

Приспів:
Синії очі, чорнії брови -
Мрійно шепочуть хвилі дніпрові...
Пісню десь чути, зорі сіяють,
Сивий Славута човен гойдає...
Хвилі дніпрові мрійно шепочуть -
Чорнії брови,  синії очі..

Про нашу згадую весну,
Прекрасну і тривожну,
На пісню щастя оберну
Сльозинку твою кожну...
Десь пропада зорі*
В траві росою тане
Не тільки кольором очей
Близька мені кохана...

Приспів.','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6233746'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6233746','Синії очі','В твоїх очах - душа твоя
Все та ж кохана, юна.
Для мене радісно сія,
Торкає серця струни,
І струни радісно звучать
Про дні, сади квітчасті,
В твоїх очах небес*
І щастя, щастя, щастя...

Приспів:
Синії очі, чорнії брови -
Мрійно шепочуть хвилі дніпрові...
Пісню десь чути, зорі сіяють,
Сивий Славута човен гойдає...
Хвилі дніпрові мрійно шепочуть -
Чорнії брови,  синії очі..

Про нашу згадую весну,
Прекрасну і тривожну,
На пісню щастя оберну
Сльозинку твою кожну...
Десь пропада зорі*
В траві росою тане
Не тільки кольором очей
Близька мені кохана...

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6233746_l1','pisniua_6233746','YouTube','https://www.youtube.com/watch?v=9f7JJrKuu7Q','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6233297','Новий Рік','Музика: Олег Майовський Слова: Олег Майовський. Виконує: Олеся Закатюра, Сергій Закатюра','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Біли снігом кружляє
Вітерець в тихім гаї,
І дерева дрімають
В солодкім сні,
Бо на дворі вже зима,
Грає в сніжки дітвора,
А мороз малює казку
На вікні.
Вже до кожного дому
До святкового столу
Добрим людям на втіху
Йде Новий Рік!
Хоч старого року жаль,
Залишайте біль й печаль
Та візьміть найкращий спогад
В Новий рік!

Приспів:
Новий Рік
Вже ступає на поріг,
Новий Рік
Сипле снігом нам до ніг,
І у колі друзів знов
Ми зберемось всі разом,
Новий Рік
Хай дарує всім любов!

Щоб усмішок багато
Було всім на свято,
Хай несе нам здоров''я,
Цей Новий рік!
Щоб росли щасливо діти
І цвіли кохання квіти,
Хай любов прийде у хату
В Новий Рік!

Приспів. (2)

Новий Рік
Хай дарує всім любов!
Хай Ісус дарує всім любов!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6233297'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6233297','Новий Рік','Біли снігом кружляє
Вітерець в тихім гаї,
І дерева дрімають
В солодкім сні,
Бо на дворі вже зима,
Грає в сніжки дітвора,
А мороз малює казку
На вікні.
Вже до кожного дому
До святкового столу
Добрим людям на втіху
Йде Новий Рік!
Хоч старого року жаль,
Залишайте біль й печаль
Та візьміть найкращий спогад
В Новий рік!

Приспів:
Новий Рік
Вже ступає на поріг,
Новий Рік
Сипле снігом нам до ніг,
І у колі друзів знов
Ми зберемось всі разом,
Новий Рік
Хай дарує всім любов!

Щоб усмішок багато
Було всім на свято,
Хай несе нам здоров''я,
Цей Новий рік!
Щоб росли щасливо діти
І цвіли кохання квіти,
Хай любов прийде у хату
В Новий Рік!

Приспів. (2)

Новий Рік
Хай дарує всім любов!
Хай Ісус дарує всім любов!');
