INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6233555','Лист з Італії','Музика: Ігор Жук Слова: Ігор Жук. Виконує: Ігор Жук','uk','ukraine_1991',NULL,'2012','Інформаційний бюлетень ІКААПУ Інформ №1 (191) 2012 рік',NULL,'Іванку, Іванку, з того боку ярку,
З того боку ярку! -
Пішла би-м до тебе, пішла би-м до тебе -
Взяла вода кладку...

...А зима тут, Іванку, смішна: ні морозу, ні снігу.
Гори є, але в них ти би вівці не дуже напас...
Бережи там дітей. Привезу вам з Італії фіґу -
То солодке таке; там росте - може, буде і в нас.

Я щодня бачу море... І небо - Іва! - що за небо!..
В нас такого нема, все - то гори, то дощ, то жнива...
Я, Іванку, нарешті навчилася спати без тебе;
Але сплю ще сама! - то і ти там шануйся, Іва!..

А легіники тут - як гуцули: чорняві і горді, -
Тільки ти все мовчиш, а вони - як те "Радіо Люкс"...
Тут один вже поліз... Ну, дістав, як належить, по морді -
Аж господар спитав, що то з ним - тихо буркнув, що флюс...

А як ще не дістав, то хвалився, що купить ми хату,
І що певно си вженить, як я тобі лишу дітей...
Ой, Іва... Я сміюся - а як то дожити до свята!..
Тут Різдво трохи скорше, ніж в нас - то дотерплю, ачей...

Я, Іванку, не вмію писати такими словами,
Як ото в серіалах. Та й сам ти казав, що то кіч.
Я купила сорочку тобі і спідницю для мами -
І до тої сорочки я прошепотіла всю ніч...

Мій господар питав, чи не маєш ти там інтернету...
Я кажу: якби мав, чи ж би мила я вам унітаз?..
А дипломи і мого, і твого, Іва, факультету
Вже не варті і свого паперу - що в них, що у нас...

Пишеш, вибори знов... Голосуй. Я не дуже ідейна.
Ми з тобою вже мерзли - і що нині маєм за все?
Мій синьйор все не вірить, що я розумію Ейнштейна;
Засміюся: я що! - он філософ маржинку пасе...

Ти не сердься, Іва! - то я так, передихала морем...
А яке тутай небо, Іванку, без тебе пусте!..
Я вже скоро, я скоро приїду... Ми ніч проговорим,
І до ранку та дірка, що знов привезу, заросте...','["pisni.org.ua", "cat:emigration", "cat:socialno-pobutovi", "Пісні про еміґрацію", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6233555'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6233555','Лист з Італії','Іванку, Іванку, з того боку ярку,
