INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6235246','Бонна','Слова: Леся Карпінська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Хочеться нині зібрати
Квіти найкращі землі...
Звідки ж тоді могли знати -
Зовсім були ми малі.
Ви ж, така горда й красива,
Впевнено вірили в нас -
Вкотре виводили в люди
"Зовсім пропащий вже" клас.

Приспів:
Нині ж бо Ви - королева,
Й через роки - чарівна,
Перша моя наречена —
Класнице рідна моя.
Справжня бо Ви примадонна,
Вперто наслідують Вас
Юні принцеси... О, бонно!
Вечір сьогодні для Вас!

Трішки, як мати, сувора,
Нишпорка і як сестра,
Ви на буденних незгодах
Нас научали життя.
З Вами ішли до вершини,
Сміхом ставав ревний плач,
Вдома батьки за провини
Майже не лаяли нас.

Приспів.

Подругам це не збагнути -
Доля давала Вам шанс:
Тон фешенебельних блисків
Як поміняти на вальс?
Скільки їх, вчених, по світу
Шану збирають давно.
Вам в нагороду клас п''ятий
Знову навчати дано!..

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6235246'), datetime('now')),datetime('now'));
