INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6230858','Батеньку-голубоньку','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,'1976','"Пісні Тернопільщини". Пісенник. - Вип.1. - Київ: Муз. Україна, 1989.','Джерело: П. Медведик. 1976. Жабиня Зборівського р-ну. Від Марії Карабін (1904, 4 кл.). Мелодію розшифрував 3. Храпун. 182. Пісні Тернопільщини: Календарно-обрядова та родинно-побутова лірика: Пісенник. Вип. 1. / Упоряд.: С.І. Стельмащук, П.К. Медведик. Вступ. ст. П. Медведика. — К.: Муз. Україна, 1989.','Батеньку-голубоньку,       | (2)
