INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_622972','Одна калина','Музика: Руслан Квінта Слова: Віталій Куровський. Виконує: Софія Ротару, Василь Білоцерківський','uk','ukraine_1991',NULL,NULL,NULL,'Виконує: Софія Ротару, в оригіналі тональність вища за подану на 1,5 тона. Підбір акордів: Kolivan','Вступ:  Dm Am  E  Am
