INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6237940','Вишита перлина','Слова: Леся Любарська','uk','ukraine_1991',NULL,NULL,'записано в м. Борщів',NULL,'Вишивала мати у садочку
Дорогому синові сорочку.
Кольори найкращі вибирала,
Щоб у сина доля розквітала.

Приспів:
Вишита сорочка — український стрій,
Це твоє коріння, сину дорогий!
В ній краса дівоча, сила козаків
І землі твоєї неповторний спів!

Вишивала китиці калини,
Щоб горнувся син до Батьківщини.
Чорний хрестик має пригадати,
Як страждала Україна-мати.

Приспів.

Пролетіли роки за роками,
Син благословення просить в мами.
А на грудях вишита перлина,
Що матуся берегла для сина!

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6237940'), datetime('now')),datetime('now'));
