INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6241695','Я поклав своє кохання на вівтар','Музика: Степан Гіга Слова: Анатолій Фіглюк. Виконує: Степан Гіга','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Осінь залистопадила,
У душі задощило,
Ти кохання не зрадила,
Ти його загубила...
Те, що серцем я вимріяв,   |
Зберегти не змогла ти,     |
Журавлиному вирію          |
Віддала на крилята.        | (2)

Приспів:
А я поклав своє кохання    |
На вівтар                  |
І його благословив         |
Небесний цар,              |
А ти любов мою розбила,    |
Мов кришталь,              |
І за тим тобі, що сталося, |
Не жаль...                 | (2)

Були ночі вінчальними,
Птаха щастя кружляла,
Та з гіркими печалями
Нас журба повінчала...
Нас любов повінчала,
Не Всевишнього волею,      |
А твоїм небажанням         |
Не зустрілися з долею,     |
Розминулись з коханням...  | (2)

Приспів.

Не Всевишнього волею,      |
А твоїм небажанням         |
Не зустрілися з долею,     |
Розминулись з коханням...  | (2)

Приспів.','["pisni.org.ua", "cat:lirychni", "cat:nostalgia", "Пісні про кохання, ліричні", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6241695'), datetime('now')),datetime('now'));
