INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6240477','А мій милий чорнобривий...','Українська народна пісня. Виконує: Черкаський народний хор','uk','ukraine_before_1917',NULL,NULL,'Інтернет',NULL,'А мій милий чорнобривий              |
Вареничків хоче.                     | (2)

Навари, мила! Навари, мила!          |
Навари, у-ха-ха, моя чорнобривая!    | (2)

Ой, я ж дрівець не маю,
Милий мій миленький.
Ой, я ж дрівець не маю,
Голубе сизенький.

Нарубай, мила! Нарубай, мила!        |
Нарубай, у-ха-ха, моя чорнобривая!   | (2)

Ой, я ж силоньки не маю,
Милий мій миленький.
Ой, я ж силоньки не маю,
Голубе сизенький.

То вмирай, мила! То вмирай, мила!    |
То вмирай, у-ха-ха, моя чорнобривая! | (2)

Де ж ти мене поховаєш,
Милий мій миленький?
Де ж ти мене поховаєш,
Голубе сизенький?

В кропиві, мила. В кропиві, мила.    |
В кропиві, у-ха-ха, моя чорнобривая. | (2)

Що ти на мені посадиш,
Милий мій миленький?
Що ти на мені посадиш,
Голубе сизенький?

Будяки, мила, лопухи, мила.          |
Будяки, лопухи, моя чорнобривая.     | (2)

З ким ти будеш доживать,
Милий мій миленький?
З ким ти будеш доживать,
Голубе сизенький?

Із кумой, мила. Із кумой, мила.      |
Із кумой, у-ха-ха, моя чорнобривая.  | (2)

А пішли додомоньку,
Милий мій миленький,
Вареничків наварю,
Голубе сизенький.

Не жартуй, мила! Не жартуй, мила!    |
Не жартуй, у-ха-ха, моя чорнобривая! | (3)','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6240477'), datetime('now')),datetime('now'));
