INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6237178','Поруч ти','Музика: Людмила Тимченко Слова: Людмила Тимченко. Виконує: ТамДеМи','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Ти розкажи мені
Про всі складні шляхи -
Ми подолаємо з тобою вдвох!
І хай не буде сліз,
Ви посміхніться всі,
Дарую, друзі, Вам
Тепло й любов!

Я не одна, я не боюсь:
Зі мною ти,
Мій вірний друг!
Пробач мені за все,
Що було не так.
І зрозумієш ти мене,
А я тобі пораду дам,
Бо щирість почуттів
Важливий то знак.

Приспів.

Буває важко на душі,
Та знаю я, що поруч ти,
Підтримаєш мене
І радість несеш.
Я наберу твій телефон,
Почую там твоє "Ало!"
І смуток відійде,
Забуду про все.

Приспів. (2)','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6237178'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6237178','Поруч ти','Приспів:
