INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6242144','Боже, Боже, што ся стало','Українська народна пісня. Виконує: Леся Горлицька','uk','ukr_ssr_1919_1991',NULL,'1928','альбом "З Лемківського краю", 2008 р.','Пісня розшифрована з записів 1928 р., наданих Вальтером Максимовичем (США) в 2007 р., текст пісні також переданий Вальтером Максимовичем (США) в 2007 р. в Ждині (Польща) на Міжнародному фестивалі лемківської культури.','Боже, Боже, што ся стало,
Боже, Боже, што ся стало,
Же на яблони, же на яблони
Яблок мало...

Ци не било, ци опали,
Ци не било, ци опали,
Ей, ци іх хлопці, ей, ци іх хлопці
Пообривали...

Били, били, не опали,
Били, били, не опали,
Іно іх хлопці, іно їх хлопці
Пообривали...

Били, били, але квасни,
Били, били, але квасни,
Пообривали іх, пообривали іх
Хлопці красни...

Боже, Боже, што мі с того,
Боже, Боже, што мі с того,
Ей, же я пішла, ей, же я пішла
За старого...

Ходив до ня цілу зиму,
Ходив до ня цілу зиму,
Ей, пущала м го під перину,
Ей, пущала м го під перину','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6242144'), datetime('now')),datetime('now'));
