INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6242144_l1','pisniua_6242144','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6233252','Зійшла вже зірка','Українська народна пісня. Виконує: Діана Глухова','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зійшла вже зірка на небозводі,
Ясне проміння на землю шле,
Князів багатих, ген, аж зі Сходу
До Вифлеєму вона веде.
Йдемо за світлом ясної зірки,
Там десь лежить Господнє дитя,
В бідінім вертепі в яслах на сіні
Він спочиває творець життя.

Вже херувими пісню співають:
Богові слава, мир усім вам!
Щоб добру волю на Бога мають,
Що служать правді своїм життям.
Увесь наш нарід, вся Україна,
Палкі й гарячі наші серця
З любов''ю линуть до Вифлеєму,
Де Бог-дитятко й Мати свята!

Зійшла вже зірка на небозводі,
Ясне проміння на землю шле,
І нас, люд вільний, аж з України
До Вифлеєму вона веде.
Духа в покорі, серця готові,
Підемо скласти дари свої,
Милий Ісусе, прийми готовий
Наш подарунок - любов Тобі!','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6233252'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6233252','Зійшла вже зірка','Зійшла вже зірка на небозводі,
Ясне проміння на землю шле,
Князів багатих, ген, аж зі Сходу
До Вифлеєму вона веде.
Йдемо за світлом ясної зірки,
Там десь лежить Господнє дитя,
