Милий Ісусе, прийми готовий
Наш подарунок - любов Тобі!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6233252_l1','pisniua_6233252','YouTube','https://www.youtube.com/watch?v=UjdV_DK-YCE','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6243042','Спогади','Музика: Леонід Попернацький Слова: Володимир Матвієнко. Виконує: Оксана Голуб','uk','ukraine_1991',NULL,NULL,'Продюсер',NULL,'Де пралісів і рік Полісся,
Лечу думками до села,
Мої дороги простяглися,
В добрі й любові - два крила.
Там чисте небо і дорога,
Там яснозорі почуття...
Кудись біжить ріка розлога,
Моєї правди і життя.

Приспів:
Мрію туманами осені,
Літо минуло давно...
Спогади, спогади, спогади -
Ніби червлене вино...
Мрію туманами осені,
Давнє наснилось в красі...
Спогади, спогади, спогади -
Наче лелеки в росі...

Лунай, моя осіння музо,
В душі прекрасне не мине,
Мої нові і давні друзі,
Земля і небо в нас одне.
Та тільки спогад розповнився
І все минуле ожило,
І сонце скроплене поліссям,
І знов лелеки над селом.

Приспів','["pisni.org.ua", "cat:druzhba", "cat:poliski", "Пісні про дружбу", "Пісні з Полісся"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6243042'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6243042','Спогади','Де пралісів і рік Полісся,
Лечу думками до села,
Мої дороги простяглися,
В добрі й любові - два крила.
Там чисте небо і дорога,
Там яснозорі почуття...
Кудись біжить ріка розлога,
Моєї правди і життя.

Приспів:
Мрію туманами осені,
Літо минуло давно...
Спогади, спогади, спогади -
Ніби червлене вино...
Мрію туманами осені,
Давнє наснилось в красі...
Спогади, спогади, спогади -
Наче лелеки в росі...

Лунай, моя осіння музо,
В душі прекрасне не мине,
Мої нові і давні друзі,
Земля і небо в нас одне.
Та тільки спогад розповнився
І все минуле ожило,
І сонце скроплене поліссям,
І знов лелеки над селом.

Приспів');
