INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6230144','Ой у полі, в полі','Українська народна пісня. Виконує: Майя Негребецька','uk','ukraine_before_1917',NULL,NULL,'Збірка колядок "Колядуймо нині"',NULL,'Ой, у полі, в полі там стоїть стаєнка.
Там Ісусик народився, Божая дитинка.

Пастушки у полі стерегли ягнята,
Як новину ту почули, прибігли вітати.

Прибігли, прибігли та й стали питати,
Чи дозволить Божа Мати Ісуса вітати.

Ісусе, Ісусе, рожевий цвіточку,
Даруй щастя, даруй долю в оцю хатиночку.','["pisni.org.ua", "cat:kolyadky", "cat:narodni", "Колядки", "Народні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6230144'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6230144','Ой у полі, в полі','Ой, у полі, в полі там стоїть стаєнка.
Там Ісусик народився, Божая дитинка.

Пастушки у полі стерегли ягнята,
