INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6238246','Колисанка ночі','Музика: Ірина Музика Слова: Наталя Гуркіна. Виконує: Ірина Музика','uk','ukraine_before_1917',NULL,NULL,NULL,'Аранжування - Сергій Степанів.','Заснули котенята,
Бачать сни качата,
Сонечко на небі теж спить.
Нічка усе вкрила,
Коси розпустила,
Колискова пісня летить.   | (2)

Сплять у стайні коні,
В зоопарку - поні,
Квіточка в садочку теж спить.
І дерева й трави
Бачать сни дубраві,
Зіронька на небі блищить. | (2)

Сплять маленькі діти,
Казками сповиті,
Пісенька любові дзвенить.
Щоб приколисати,
Сни подарувати,
Ніжно обіймати в цю мить.
Щоб заколихати,
Спокій дарувати,
Колисанка ночі летить...','["pisni.org.ua", "cat:kolyskovi", "Колискові"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6238246'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6238246','Колисанка ночі','Заснули котенята,
