INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6231644','Пісня для тебе','Музика: Платон Майборода Слова: Михайло Ткач. Виконує: Анатолій Мокренко, Рената Бабак','uk','ukraine_1991',NULL,NULL,'Пісенник 90',NULL,'Літа за літами -
За обрій крильми,
За обрій з дитинства
Злітаємо ми.
Та як би не кликав,
Не звав виднокруг:
На довгій дорозі,
Як віра в тривозі,
Потрібен товариш    |
І друг.             | (2)

Приспів:
Без неба нема висоти,
Дороги єднають мости,
І радість - не радість
Без друга,
Як пройдений шлях
Без мети.

За втомленим літом -
Холодна зима...
Бентежному серцю
Спокою нема.
Як часом заб''ється
У тихій журбі:
Усе, що зробили,
Навік полюбили,
Згадаєм, як сни     |
Голубі.             | (2)

Приспів.

І сонце, як вперше,
Зійде молоде,
На наші дороги
Тепло покладе.
І хтось, може, скаже:
Ми йшли недарма,
У щасті і в тузі
Були з нами друзі,  |
А кращої долі нема. | (2)

Приспів','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6231644'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6231644','Пісня для тебе','Літа за літами -
