INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6231644_l1','pisniua_6231644','YouTube','https://www.youtube.com/watch?v=YyC-hbRm0RY','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6233271','Новорічна','Музика: Сергій Андрущак Слова: Сергій Андрущак. Виконує: Еліза Андрущак Сергій Андрущак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Там, де гори сховались за хмарами,
У льодовому замку живе Дід Мороз,
Він чекає пори, коли листя спаде
І зима до нас в гості прийде!

Він в дорогу тоді вирушає скоріш,
Подарунки малятам у торбу кладе,
Через гори круті нам ялинку несе
І в дорозі співає про це.

Ми прикрасим ялинку гірляндами,
Срібний дощик проллється на пишні гілки,
Кольорова красуня посміхнеться до нас,
Дід Мороз гукне: "Забаві час!"

Там, де гори сховались за хмарами,
У льодовому замку живе Дід Мороз,
Він чекає пори, коли листя спаде
І зима до нас в гості прийде!

Він в дорогу тоді вирушає скоріш,
Подарунки малятам у торбу кладе,
Через гори круті нам ялинку несе
І в дорозі співає про це.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6233271'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6233271','Новорічна','Там, де гори сховались за хмарами,
У льодовому замку живе Дід Мороз,
Він чекає пори, коли листя спаде
І зима до нас в гості прийде!

Він в дорогу тоді вирушає скоріш,
Подарунки малятам у торбу кладе,
Через гори круті нам ялинку несе
І в дорозі співає про це.

Ми прикрасим ялинку гірляндами,
Срібний дощик проллється на пишні гілки,
Кольорова красуня посміхнеться до нас,
Дід Мороз гукне: "Забаві час!"

Там, де гори сховались за хмарами,
