INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6237797','Є тільки мить','Музика: О. Зацепин Слова: Ігор Федчишин','uk','ukraine_1991',NULL,NULL,'Пісня О.Зацепина та Л.Дербенева з кінофільму "Замля Санникова"',NULL,'Клопітно нам в цьому світі бурхливому,
Є тільки мить, що ласкає серця,
Є тільки мить між вчорашнім та нинішним,
Саме вона має назву - життя!

З року-у-рік ми на спокій загадуєм,
Він лиш для тих, хто ніде не спішить,
А для зорі, що палає і падає,
Є тільки мить, обворожлива мить.

Вмить промайне все життя наше праведне,
А за гріхи дорікати не смій,
Миті одній ми будуємо пам''ятник,
Миті одній, тільки миті одній.

Щастям назвем ми всі миті поблажливо,
Лихо і сум заберем в небуття,
Є тільки мить між минулим і завтрашнім,
Саме вона має назву - життя!','["pisni.org.ua", "cat:translations", "Переклади іноземних пісень"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6237797'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6237797','Є тільки мить','Клопітно нам в цьому світі бурхливому,
Є тільки мить, що ласкає серця,
Є тільки мить між вчорашнім та нинішним,
Саме вона має назву - життя!

З року-у-рік ми на спокій загадуєм,
Він лиш для тих, хто ніде не спішить,
А для зорі, що палає і падає,
Є тільки мить, обворожлива мить.

Вмить промайне все життя наше праведне,
А за гріхи дорікати не смій,
Миті одній ми будуємо пам''ятник,
Миті одній, тільки миті одній.

Щастям назвем ми всі миті поблажливо,
Лихо і сум заберем в небуття,
Є тільки мить між минулим і завтрашнім,
Саме вона має назву - життя!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_6237797_l1','pisniua_6237797','http://musicfiles.ru','http://musicfiles.ru','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6234776','Новий рік','Музика: Марія Бурмака Слова: Наталя Забіла. Виконує: Марія Бурмака','uk','ukraine_1991',NULL,NULL,'диск',NULL,'У нас сьогодні весело
В дитячому садку:
Ялиночку принесено,
Поставлено в кутку!

Приспів:
Новий Рік                |
Знов приходить на поріг! |
Новий Рік -              |
Подарунки для усіх!      | (2)

Так гарно-гарно прибрано
Ялиночку у нас:
І вогниками срібними,
І золотом прикрас.

Приспів.

Ялиночко, красунечко,
Ліхтарики блищать,
Хороші подаруночки
Під вітами лежать!

Приспів.

А ми в долоні плещемо,
Співаємо пісень -
Нам дуже, дуже весело
В такий веселий день!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6234776'), datetime('now')),datetime('now'));
