INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6245570','Весільна для доні','Музика: Володимир Домшинський Слова: В. Сав''юк. Виконує: Богдан Сташків','uk','ukraine_1991',NULL,NULL,'http://smoz.ru/, аудіозапис',NULL,'Застелила осінь рушничок весільний,
На моїм подвір''ї гості і рідня.
В серці промайнуло лебединим пір''ям
Донечки дитинство — золота пора.
На подвір''я вийшла молода лебідка,
Радісно скотилася матері сльоза,
Рушничка торкнулось лебедине пір''я,
В вирій відлітає донечка моя.

Приспів:
Ой, на-на, на-на-на.
Моя ти дана,
Моя дитино,
Моя доню дорога.
Ой, на-на, на-на-на.
І світ жаданий,
Моя ти зіронько
Небесна і земна.

О, моя лебідко, о, моя дитино,
І для мене пісня ту, що Бог послав.
І сьогодні стала молода дружина,
Цю весільну ватру, а тож Бог розклав.
О, моя лебідко, о, моя дитино,
І летиш у вирій щастя і добра.
Збережи довіку вірність лебедину,
Пам''ятай, дитино, батьківські слова!

Приспів. (3)','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6245570'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6245570','Весільна для доні','Застелила осінь рушничок весільний,
