INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6243454','Серце моє для тебе','Музика: Марта Шпак Слова: Марта Шпак. Виконує: Марта Шпак','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В Україні Євро свято
Розпалив в душі огонь,
Крок до світу, перемоги
Робить чемпіон!
Там, де гори, синє море,
Де душа співає,
Світ футболу щирим серцем |
Двері відкриває!          | (2)

Приспів:
Крок за кроком грай! Грай!
Ну, давай, перемагай!
Допоможи нам, небо!
Ти надію не втрачай
І від нині пам''ятай:
Серце моє для тебе!       | (3)

З нами друзі
Й панство польське
Теж запрошують на матч.
Футболісти, станьте в коло,
Починаєм Євро матч!
Вже на полі вся Європа,
Як одна родина,
Серце своє відкриває      |
Євро Vіva!                | (2)

Приспів. (2)

Серце моє для тебе!       | (2)','["pisni.org.ua", "cat:himny-marshi", "Гимни та марші"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6243454'), datetime('now')),datetime('now'));
