INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6235093','Щедрівочка щедрувала','Українська народна пісня. Виконує: Волинський народний хор, Театр Пісні "Джерела"','uk','ukraine_before_1917',NULL,NULL,'Співає Волин. народний хор / © Видавництво: "Волин. книга", ВАТ "Волин. обл. друкарня", Луцьк, 2008 р.','Українська народна творчість, українська пісенність, художній світ.','Щедрівочка щедрувала,
До віконця припадала.
Що ти, тітко, напекла,
Неси нам до вікна,
Чи вареник, чи пиріг
Неси нам за поріг.

Приспів:
Щедрик, ведрик,        |
Дайте вареник,         |
З грушами пироги,      |
Здоровенькі були.      | (2)

Щедрівочка, щедрівочка
Добра з медом горілочка,
А без меду не така,
Дайте нам п''ятака.
А п''ятак не такий,
Дайте руб золотий.

Приспів.

Ми щедрівки заспівали,
За щедрівки ленти дали.
Ленти в коси заплетем, |
І в таночок підем.     | (2)

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:narodni", "cat:shchedrivky", "Дитячі пісні", "Народні пісні", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6235093'), datetime('now')),datetime('now'));
