INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6240644','Ще осінь зовсім молода...','Музика: Сергій Бабкін Слова: Федір Савлук. Виконує: Сергій Бабкін','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ще осінь зовсім молода,
Не встигла перейтись полями,
Мінлива зрадила вода -
Тебе не стало поміж нами...

Освячений Всевишнім шлях,
Мов небо сонечком на сході,
Живе душа твоя в піснях,
В полотнах зітканих мелодій!..

Співаєш з ангелами десь,
Обнятий їхніми крилами...
Втішає голос від небес:
Ми всі живі — не плачте, мамо!..

Не плачте, мамо!..               | (6)

Ми всі живі — не плачте, мамо!.. | (8)','["pisni.org.ua", "cat:nostalgia", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6240644'), datetime('now')),datetime('now'));
