INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6244399','В день народження твого','Музика: Олександр Семенців Слова: Олександр Семенців. Виконує: Дует Розмай (США)','uk','ukraine_1991',NULL,NULL,'2-й диск- "Очі-волошки"',NULL,'Ось сьогодні
День народження твій!
Хай збуваються бажання
Заповітних твоїх мрій!
Хай добра повниться чаша,
Щоб з роси тобі й з води!
Щоб безхмарних довгих років
Й не зазнати щоб біди!

Приспів:
Добре, коли друзі згадують,
І подарунками радують,
Щоб була подія ця світла
Й світилась усмішка привітна!
В День народження твого
Побажають всі друзі того,
Щоби доля всміхалась, здоров''я було,
Щоби радість життя принесло!

Ось сьогодні
День народження твій!
Хай сльози гірке пізнання
Не торкнеться твоїх вій!
Хай задумане здійсниться,
Щоб невдачі відійшли,
Щоб хотілося й моглося
І сади в душі цвіли!

Приспів.

В День народження твого
Побажають всі друзі того,
Щоби доля всміхалась, здоров''я було,
Щоби радість життя принесло!

Приспів.

В День народження твого              |
Побажають всі друзі того,            |
Щоби доля всміхалась, здоров''я було, |
Щоби радість життя принесло!         | (2)','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6244399'), datetime('now')),datetime('now'));
