INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6244673','Ха-ха-ха','Музика: Михайло Хома, Олег Турко Слова: Михайло Хома. Виконує: DZIDZIO','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Заходжу в магазин на пиво розливне,
