INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6246178','У лузі червона калина','Українська народна пісня. Виконує: Веселі музики','uk','ukraine_1991',NULL,'1993',NULL,'Обробка Лисоконь О.П, Хитряков С.П. у виконанні фольклорного ансамблю Національної філармонії України "Веселі Музики" 1993 р.','У лузі, у лузі червона калина.
Там дівчина мила віночок, увила,
