INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_624797','Ой у вишневому садочку...','Українська народна пісня. Виконує: Чарівна','uk','ukraine_before_1917',NULL,NULL,'Багато хто співає:-)','Пісня гарно звучить коли грати вальсом, а саме: Удар по одній з басових струн і згодом два щипка 3 не-басових струн. В приспіві можна замість щипка робити удар. azovchanka: Улюблена жартівлива пісня, яка виконується синтез-гуртом "Чарівна". Як завжди використовуються акустичні інструменти: бандура, скрипка, гітара, бубен. Запис зроблено у 1993р. Нова редакція - 2007р.','Ой у вишневому садочку
Там соловейко щебетав,
Фіть-фіть-фіть, тьох-тьох-тьох, |
А-я-яй, ох-ох-ох,               | (2)
Там соловейко щебетав.          |

