INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6246195','Новий Рік','Українська народна пісня. Виконує: Ріка життя','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Довгожданий день прийшов,
В серці відгук він знайшов,
Цей зимовий час подарував
Своє тепло, своє тепло...
Наче в дивовижнім сні
Навкруг засяяли вогні,
Годинник "північ" б''є,
І враз нещастя утекло!

Приспів:
З Новим Роком -
Годинник вже б''є
Любе свято твоє і моє!
З Новим Роком!
Летять по світу бажання!
З Новим Роком -
Годинник вже б''є
Любе свято твоє і моє!
З Новим Роком!
Усім добра і кохання!

Ми піднімаєм келих свій
За чистоту відвертих мрій,
За вдачу молоду,
За щастя і палку любов!
Нехай минулії роки
Не подадуть уже руки,
Бо ще не раз в житті
Ми побажаєм знов і знов!

Приспів. (2)

З Новим Роком!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6246195'), datetime('now')),datetime('now'));
