INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6244991','Першокласники випускникам','Музика: Тарас Питлик Слова: Тарас Питлик','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Для вас, випускники,
Лунає дзвінок вже останній раз.
Розійдуться ваші стежки,
Покинете школу і рідний свій клас...

Приспів:
А ми будем вас пам''ятати,
І приклад із вас будем брати.
Учитись як ви, старатись як ви,
Як ви!

Хай вам у житті щастить,
Хай Бог береже і шанує вас.
Лиш в школу ще приходіть,
Бо так полюбили і звикли до вас!

Приспів. (2)    Фонограма-мінус (mp3, 192 kbps)','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6244991'), datetime('now')),datetime('now'));
