INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6246776','Грають труби над Дністром','Музика: народна Слова: Олександр Колесса','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'Збірка пісень січових стрільців "Гей, Січ іде!" 1992 р.',NULL,'Грають труби над Дністром,
Кров жива пливе руслом.
Славні стрільці січовії
Ворогам несуть погром!
Гей, гей, гей, гей!
Москалям несуть погром,
Смерть, погром!

Понад Волинь грім гримить,
Галич вільний гомонить.
Гей, коли ж озветься Київ?..
Дніпро кров''ю зашумить?!?
Гей, гей, гей, гей!
Дніпро море зчервонить...

Ой, заграє в Лаврі дзвін
Радісно в цілий розгін...
І воскресне Україна
Від хвиль Сяну аж по Дін!
Гей, гей, гей, гей!
Аж до моря, аж по Дін,
Аж по Дін!

В крові велет підросте,
Сила духа розцвіте
І заблисне над народом
Волі сяєво святе!
Гей, гей, гей, гей!
Щастя сонце золоте!
Золоте!','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6246776'), datetime('now')),datetime('now'));
