INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6249644','А в нас завтра свальба буде','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські народні пісні з нотами. Засвічу свічку восковую. - Харків: Фоліо, 2002. - 289 с.','Свальба* - весілля.','А в нас завтра свальба* буде,
