INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6246940','Запорозький марш','Музика: Євген Адамцевич Слова: Олекса Ющенко. Виконує: Євген Адамцевич','uk','ukraine_before_1917',NULL,NULL,'Автор слів','Виконує: Націон. оркестр народних інструментів п/к В.Гуцала.','На Вкраїну рідну суне сила вража -
Хоче поневолить, хоче полонить.
Ти грабуєш, ляше, забираєш наше, -
Як же нам по-доброму із тобою жить?

Не на те родились ми, щоб в неволі скніти,
Щоб судилось дітям рабство та ярмо, -
Ми на посміх світу не потерпим гніту,
Ми на глум свободу нашу не дамо!

Не одного сина вражі катували,
Не один звитяжець потрапляв на гак.
Не забув підступні зрадницькі навали
Вірний щирій дружбі вславлений козак.

Закипають хвилі в морі почорнілі,
Плаче стара чайка, чуючи бої.
Нас не подолати ненависній силі,
Не знеславим чисті прапори свої!

Чуєш, вражий сину, ти за наш Батурин
І на тому світі відповідь даси.
Гомонить Вкраїна, чути звуки сурем,
Бачим вільну матір юної краси.

Бачим Україну вільну та погожу,
Бачимо онуків в щасті та добрі.
І козацьку вірну ставимо сторожу
Біля моря нашого, як в літа старі.

Дзвонять струни кобзи, вирушає військо,
Розбирає ворога страх і чорна лють.
Шлях важкий козацький проляга не близько,
Козаки за правду і за волю йдуть.

...Гей, долиною, гей, широкою козаки йдуть','["pisni.org.ua", "cat:himny-marshi", "cat:kozacki", "Гимни та марші", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6246940'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6246940','Запорозький марш','На Вкраїну рідну суне сила вража -
Хоче поневолить, хоче полонить.
Ти грабуєш, ляше, забираєш наше, -
Як же нам по-доброму із тобою жить?

Не на те родились ми, щоб в неволі скніти,
Щоб судилось дітям рабство та ярмо, -
Ми на посміх світу не потерпим гніту,
Ми на глум свободу нашу не дамо!

Не одного сина вражі катували,
Не один звитяжець потрапляв на гак.
Не забув підступні зрадницькі навали
Вірний щирій дружбі вславлений козак.

Закипають хвилі в морі почорнілі,
Плаче стара чайка, чуючи бої.
Нас не подолати ненависній силі,
Не знеславим чисті прапори свої!

Чуєш, вражий сину, ти за наш Батурин
І на тому світі відповідь даси.
Гомонить Вкраїна, чути звуки сурем,
Бачим вільну матір юної краси.

Бачим Україну вільну та погожу,
Бачимо онуків в щасті та добрі.
І козацьку вірну ставимо сторожу
Біля моря нашого, як в літа старі.

Дзвонять струни кобзи, вирушає військо,
Розбирає ворога страх і чорна лють.
Шлях важкий козацький проляга не близько,
Козаки за правду і за волю йдуть.

...Гей, долиною, гей, широкою козаки йдуть');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_624454','А ты мила','Українська народна пісня. Виконує: Юлія Дошна, Бурдон','uk','ukr_ssr_1919_1991',NULL,'1981','Аудіо-альбом "Юлія Дошна. "Там на Лемковині" (2000)','Текст подано за джерелом (взято з обкладинки аудіо-CD) зі збереженням оригінального правопису. * Тут в аудіо: "Кєд сой гвечер, кєд сой гвечер зо мном спала". Джерело: Самвидавний туристичний пісенник: Там на Лемковині помедже горами. - Літо 1981. Пісенник створений українцем із Польщі Лехом Ляхом. Ймовірно, що обробка тексту, мелодії, підбір акордів належить йому.','А ты мила, а ты мила штос думала
Кєд сой гвечер, кєд сой гвечер зо мнов спала *
Тота єдна думка моя                     |
Же ты не мій, я не твоя душко моя       | (2)

Чого єс ся, чого єс ся погнівала
Кой єс щыро, кой єс щыро не думала
Забуд мила то гніваня                   |
Бо то было на прощаня душко моя         | (2)

Од тых думок, од тых думок серце болит
Хто на двоє, хто на двоє любов ділит
Моя любов знат лем тебе                 |
Не ход гу двом, прид до мене душко моя  | (2)','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_624454'), datetime('now')),datetime('now'));
