INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6249797','До побачення, школо!','Музика: Іван Пустовий Слова: Володимир Семеновський','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Скільки весен цвіла нам калина
Й пелюстками стелилась до ніг!
Скільки літ нам стелилась стежина
На шкільний заповітний  поріг!

Приспів:
Кличуть юних дзвінкі видноколи
І прощальний відлунює вальс.
До побачення, школо,
До побачення, школо,
Ми тебе, ми тебе ще згадаєм не раз!..

Ці літа журавлино промчали -
Кличе в коло замріяний вальс,
У очах наших сльози печалі,
Бо уже розставатися час...

Приспів.

Зрине все, як на кіноекрані -
Перша вчителька, перший урок...
До побачення, вчителько-мамо,
Ви посіяли в серці добро!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6249797'), datetime('now')),datetime('now'));
