INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_624940','Козак від’їжджає','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Козак від''їжджає,
Дівчинонька плаче:
"Куди їдеш, козаче?
Козаче - соколю,
Візьми мене із собою
На Вкраїну далеку".

"Дівчинонько мила,
Що будеш робила
На Вкраїні далекій?"
"Буду хустки прати,
Тебе, милий, доглядати
На Вкраїні далекій".

"Дівчинонько мила,
Що будеш ти їла
На Вкраїні далекій?"
"Сухий хліб з водою,
Коби, серце, із тобою
На Вкраїні далекій".

"Дівчинонько мила,
Де будеш ти спати
На Вкраїні далекій?"
"В степу під вербою,
Коби, серце, із тобою
На Вкраїні далекій".','["pisni.org.ua", "cat:kozacki", "cat:kubanski", "Козацькі пісні", "Кубанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_624940'), datetime('now')),datetime('now'));
