INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6250374','Білі мухи','Музика: Віктор Музичук Слова: Максим Рильський, Віктор Музичук. Виконує: Віктор Музичук, Вікторія','uk','ukraine_1991',NULL,'1997','авторське подання','Пісня із альбому Віктора Музичука та гурту "Вікторія" "Тусовка", виданого в Києві Національною аудіо компанією (NAC) в 1997 р.','Білі мухи налетіли -
Все подвір''я стало біле.
Не злічити білих мух,
Що летять, неначе пух.
Галю, Петрику, Кіндрате,
Годі, ледарі, вам спати.
І побігли до санчат
Галя, Петрик і Кіндрат.
...Кіндрат! ...Кіндрат!

Всі з гори летять щодуху,
Щоб впіймати білу муху.
А санчата їм усім
Змайстрував старий Максим.
...Максим! ... Максим!

Білі мухи налетіли, налетіли -
Все подвір''я стало біле, стало біле.
Не злічити білих мух, білих мух,
Що летять, неначе пух.
...Як пух! ...Як пух!

P.S.:
Гарний віршик, любі діти?
Легко з музикою вчити?
То ж якщо не час ще спати,
То біжіть мерщій гуляти.
Ну а зараз я усім
Вірш дорослим розповім.
Галя, Петрик і Кіндрат
Десь дістали автомат.
Хто ж віддав цю зброю їм?
Партизан старий Максим!
...Максим! ... Максим!','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6250374'), datetime('now')),datetime('now'));
