INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6247075','У літній вечір над Дніпром','Музика: Анатолій Кулик Слова: Юрій Удод. Виконує: Хор Київського училища культури','uk','ukraine_1991',NULL,'2004','Автор слів','Запис 2004 року','У літній вечір над Дніпром
Удвох з тобою ми зійшлися.
Не розійтися нам обом,
Коли вуста палкі злилися...

Блищить від місяця вікно
І мальви тишу доглядають.
І спить село уже давно,
Лиш вишні соки наливають...

А ніч, немов жита в полях,
Теплом своїм нас обнімає.
Уже і вітер по ярах
З Дніпра на гору не злітає...

І нам усе, як перший раз,
Коли зустрілися з тобою.
Надовго зустріч затяглась
У літній вечір над рікою...','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_6247075'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_6247075','У літній вечір над Дніпром','У літній вечір над Дніпром
Удвох з тобою ми зійшлися.
Не розійтися нам обом,
Коли вуста палкі злилися...

Блищить від місяця вікно
І мальви тишу доглядають.
І спить село уже давно,
Лиш вишні соки наливають...

А ніч, немов жита в полях,
Теплом своїм нас обнімає.
Уже і вітер по ярах
З Дніпра на гору не злітає...

І нам усе, як перший раз,
Коли зустрілися з тобою.
Надовго зустріч затяглась
У літній вечір над рікою...');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_6248879','Україна-вишиванка','Музика: Олег Харитонов Слова: Петро Мага. Виконує: Катерина Бужинська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Нитка сонячного ранку.
Нитка пісні солов''я,
Україна-вишиванка,
Ніжна матінко моя,
Ти і грішних і невинних
Пригортаєш до грудей,
Я люблю свою країну, |
Я люблю своїх людей! | (2)

Приспів:
Будьте красиві, будьте здорові,
Білі, русяві і чорноброві,
Будьте веселі, будьте багаті
В кожній оселі і в кожній хаті!

Вишиваю візерунки
Диво-травами степів,
Смаком перших поцілунків
І коханням вечорів.
Вишиваю як уклінно
Ти запрошуєш гостей,
Я люблю свою країну, |
Я люблю своїх людей! | (2)

Приспів.

Може є у світі кращі
Кольори на полотні,
Але ти єдина наша,
А у тебе ми одні.
Я тебе святу і грішну
Пригортаю до грудей!
Я люблю свою країну, |
Я люблю своїх людей! | (2)

